def _finalize_trade_automation_cycle(
    db: Session,
    *,
    tenant: Tenant,
    state: dict[str, Any],
    profile_key: str = _AUTOMATION_PERSONAL_PAPER_PROFILE,
    linked_account: BrokerageLinkedAccount | None = None,
    effective_funds: float | None = None,
    rollout_readiness: dict[str, Any] | None,
    now: datetime,
    cycle_id: str,
    monitored_open: pd.DataFrame | None = None,
    pending_orders: pd.DataFrame | None = None,
    closed_trades: pd.DataFrame | None = None,
) -> dict[str, Any]:
    _write_trade_automation_state(tenant, state, profile_key=profile_key)
    db.commit()
    runtime_state = state["runtime"]
    equity_reference = state.get("__actual_funds")
    try:
        equity_snapshot = record_trade_automation_equity_snapshot(
            tenant=tenant,
            state=state,
            profile_key=profile_key,
            cycle_at=now,
            cycle_id=cycle_id,
            monitored_open=monitored_open,
            pending_orders=pending_orders,
            closed_trades=closed_trades,
            now=now,
            effective_funds=equity_reference if equity_reference is not None else effective_funds,
        )
        runtime_state["equity_snapshot_last_error"] = None
        runtime_state["equity_snapshot_last_error_at"] = None
    except Exception as exc:  # pragma: no cover - evidence snapshots must not stop trading cycles
        equity_snapshot = None
        runtime_state["equity_snapshot_last_error"] = str(exc)
        runtime_state["equity_snapshot_last_error_at"] = _serialize_datetime(_utc_now())
    previous_fill_count = int(runtime_state.get("current_route_fill_count") or 0)
    previous_close_count = int(runtime_state.get("current_route_closed_trade_count") or 0)
    refreshed_rollout_readiness = dict(rollout_readiness or {})
    try:
        collection_metrics = _build_live_current_route_collection_metrics(tenant)
    except Exception as exc:  # pragma: no cover - defensive telemetry guard
        collection_metrics = {
            "current_route_fill_count": int(runtime_state.get("current_route_fill_count") or 0),
            "current_route_closed_trade_count": int(runtime_state.get("current_route_closed_trade_count") or 0),
            "current_route_mismatched_count": int(runtime_state.get("current_route_mismatched_count") or 0),
            "current_route_sample_status": str(runtime_state.get("current_route_sample_status") or "insufficient"),
            "mark_to_market_coverage_status": str(runtime_state.get("mark_to_market_coverage_status") or "missing"),
            "ledger_snapshot_consistency": str(runtime_state.get("ledger_snapshot_consistency") or "unavailable"),
            "metrics_source": str(runtime_state.get("metrics_source") or "").strip().lower() or None,
            "route_window_start": runtime_state.get("route_window_start"),
            "route_window_end": runtime_state.get("route_window_end"),
            "route_window_snapshot_count": int(runtime_state.get("route_window_snapshot_count") or 0),
            "current_route_latest_event_at": runtime_state.get("current_route_latest_event_at"),
            "current_route_validation_integrity": serialize_value(
                refreshed_rollout_readiness.get("current_route_validation_integrity") or {}
            ),
        }
        runtime_state["last_validation_rerun_error"] = str(exc)
    collection_phase = _build_collection_phase_state(
        rollout_readiness=refreshed_rollout_readiness,
        runtime_state=runtime_state,
        collection_metrics=collection_metrics,
    )
    _apply_collection_phase_runtime(runtime_state, collection_phase)

    if _should_auto_rerun_validation(collection_phase=collection_phase, runtime_state=runtime_state, cycle_id=cycle_id):
        runtime_state["validation_rerun_in_progress"] = True
        collection_phase = _build_collection_phase_state(
            rollout_readiness=refreshed_rollout_readiness,
            runtime_state=runtime_state,
            collection_metrics=collection_metrics,
        )
        _apply_collection_phase_runtime(runtime_state, collection_phase)
        try:
            _run_validation_export_for_collection_phase(tenant)
            runtime_state["last_validation_rerun_status"] = "succeeded"
            runtime_state["last_validation_rerun_error"] = None
            runtime_state["last_validation_rerun_at"] = _serialize_datetime(_utc_now())
            runtime_state["last_validation_rerun_event_at"] = collection_phase.get("current_route_latest_event_at")
            runtime_state["last_validation_rerun_cycle_id"] = cycle_id
            refreshed_trade_summary = get_trade_summary(
                db=db,
                current_user=_build_system_current_user(tenant, None),
            )
            refreshed_rollout_readiness = dict(refreshed_trade_summary.get("rollout_readiness") or {})
        except Exception as exc:  # pragma: no cover - defensive validation rerun guard
            runtime_state["last_validation_rerun_status"] = "failed"
            runtime_state["last_validation_rerun_error"] = str(exc)
            runtime_state["last_validation_rerun_at"] = _serialize_datetime(_utc_now())
            runtime_state["last_validation_rerun_cycle_id"] = cycle_id
        finally:
            runtime_state["validation_rerun_in_progress"] = False
            try:
                collection_metrics = _build_live_current_route_collection_metrics(tenant)
            except Exception:  # pragma: no cover - preserve prior sample metrics
                pass
            collection_phase = _build_collection_phase_state(
                rollout_readiness=refreshed_rollout_readiness,
                runtime_state=runtime_state,
                collection_metrics=collection_metrics,
            )
            _apply_collection_phase_runtime(runtime_state, collection_phase)

    _finalize_collection_audit(
        runtime_state,
        collection_phase=collection_phase,
        collection_metrics=collection_metrics,
        previous_fill_count=previous_fill_count,
        previous_close_count=previous_close_count,
    )
    try:
        automation_state_control_service.evaluate_trade_automation_state_control(
            db,
            tenant=tenant,
            state=state,
            profile_key=profile_key,
            linked_account=linked_account,
            now=now,
        )
    except Exception as exc:  # pragma: no cover - state notes must not break trading automation
        runtime_state["state_control_last_error"] = str(exc)
    try:
        hard_fault_report = automation_limited_live_safety_ladder_service.build_limited_live_hard_fault_snapshot(
            state,
            now=now,
        )
        runtime_state["limited_live_hard_fault_last_report"] = serialize_value(hard_fault_report)
        if bool(hard_fault_report.get("should_disable_allowances")):
            runtime_state["limited_live_hard_fault_rollback"] = (
                automation_limited_live_safety_ladder_service.disable_limited_live_allowances_for_fault(
                    state,
                    reason="; ".join(str(item) for item in hard_fault_report.get("blockers") or []) or "hard_fault",
                    now=now,
                    actor=_build_system_current_user(tenant, None),
                )
            )
    except Exception as exc:  # pragma: no cover - hard-fault telemetry must not break cycle finalization
        runtime_state["limited_live_hard_fault_last_error"] = str(exc)
    try:
        automation_ai_review_service.capture_trade_automation_ai_observation(
            tenant=tenant,
            state=state,
            profile_key=profile_key,
            linked_account=linked_account,
            now=now,
            cycle_id=cycle_id,
        )
    except Exception as exc:  # pragma: no cover - notes must not break trading automation
        runtime_state["ai_last_observation_error"] = str(exc)
    try:
        session_for_promotion = _build_session_snapshot(
            flatten_before_close_minutes=state["settings"]["flatten_before_close_minutes"]
        )
        now_et = session_for_promotion.get("now_et")
        session_day = None
        daily_summary = None
        if isinstance(now_et, datetime) and now_et.time() >= time(16, 0):
            session_day = now_et.date().isoformat()
            daily_summary = build_trading_safety_daily_summary(day=session_day, tenant_slug=tenant.slug)
        runtime_state["position_promotion_last_report"] = _record_position_promotion_evidence(
            state,
            now=now,
            cycle_id=cycle_id,
            session_day=session_day,
            daily_summary=daily_summary,
        )
    except Exception as exc:  # pragma: no cover - promotion evidence must not break cycle finalization
        runtime_state["position_promotion_last_error"] = str(exc)
    _write_trade_automation_state(tenant, state, profile_key=profile_key)
    db.commit()
    if (
        str(profile_key or "").strip().lower() == _AUTOMATION_PERSONAL_PAPER_PROFILE
        and bool(state.get("settings", {}).get("auto_trade_listed_options"))
    ):
        try:
            from backend.services import options_automation_service

            options_automation_service.get_options_automation_snapshot(
                db,
                current_user=_build_system_current_user(tenant, None),
            )
        except Exception:  # pragma: no cover - export refresh must not break the worker
            pass
    refreshed_rollout_readiness = _augment_rollout_readiness_with_collection_phase(
        refreshed_rollout_readiness,
        collection_phase,
    )
    return _build_snapshot_payload(
        tenant,
        state,
        profile_key=profile_key,
        linked_account=linked_account,
        equity_snapshot=equity_snapshot,
        rollout_readiness=refreshed_rollout_readiness,
        db=db,
    )


def _row_supports_automation_instrument(row: dict[str, Any], instrument_type: str) -> bool:
    normalized_instrument = _normalize_automation_instrument(instrument_type, default="equity")
    vehicle_recommendation = str(row.get("vehicle_recommendation") or "").strip().lower()
    option_execution_profile = dict(row.get("option_execution_profile") or {})
    if normalized_instrument == "equity":
        return vehicle_recommendation in {"", "equity"}
    contract_symbol = str(row.get("contract_symbol") or "").strip()
    verdict = str(row.get("verdict") or "").strip().upper()
    option_right = str(row.get("option_right") or row.get("direction") or "").strip().lower()
    contract_quality_tier = str(option_execution_profile.get("contract_quality_tier") or row.get("contract_quality_tier") or "").strip().lower()
    execution_score = float(
        pd.to_numeric(
            option_execution_profile.get("execution_score", row.get("option_execution_score")),
            errors="coerce",
        )
        or 0.0
    )
    if option_right not in {"call", "put"}:
        if verdict == "BULLISH":
            option_right = "call"
        elif verdict == "BEARISH":
            option_right = "put"
    if vehicle_recommendation and vehicle_recommendation != "listed_option":
        return False
    quality_gate = contract_quality_tier != "weak" if contract_quality_tier else True
    score_gate = execution_score >= 70.0 if execution_score > 0 else True
    return bool(contract_symbol and option_right in {"call", "put"} and quality_gate and score_gate)


def _candidate_numeric(candidate: dict[str, Any], *keys: str) -> float | None:
    for key in keys:
        value = pd.to_numeric(candidate.get(key), errors="coerce")
        if pd.notna(value):
            return float(value)
    return None


def _candidate_projected_notional(candidate: dict[str, Any], settings_state: dict[str, Any], current_equity: float) -> float:
    direct = _candidate_numeric(
        candidate,
        "projected_position_cost",
        "total_position_cost",
        "position_cost",
        "projected_notional",
        "notional",
    )
    if direct is not None and direct > 0:
        return float(direct)
    baseline_risk_percent = float(settings_state.get("risk_percent") or 0.5)
    risk_budget_notional = max(float(current_equity) * (baseline_risk_percent / 100.0) * 10.0, 100.0)
    max_notional_per_trade = float(settings_state.get("max_notional_per_trade") or 0.0)
    if max_notional_per_trade > 0:
        return min(max_notional_per_trade, risk_budget_notional)
    single_cap = max(float(current_equity), 1.0) * (float(settings_state.get("max_single_position_pct") or 12.0) / 100.0)
    return float(min(single_cap, risk_budget_notional))


def _candidate_spread_bps(candidate: dict[str, Any]) -> float | None:
    spread = _candidate_numeric(candidate, "spread_bps", "bid_ask_spread_bps", "quote_spread_bps", "live_spread_bps")
    if spread is not None:
        return abs(float(spread))
    spread_pct = _candidate_numeric(candidate, "spread_pct", "contract_spread_pct")
    if spread_pct is not None:
        return abs(float(spread_pct) * 10000.0)
    bid = _candidate_numeric(candidate, "bid", "quote_bid", "contract_bid")
    ask = _candidate_numeric(candidate, "ask", "quote_ask", "contract_ask")
    mid = _candidate_numeric(candidate, "mid", "mark", "live_price", "close", "contract_mid")
    if bid is not None and ask is not None:
        reference = mid if mid is not None and mid > 0 else (bid + ask) / 2.0
        if reference > 0:
            return abs(ask - bid) / reference * 10000.0
    return None


def _candidate_liquidity(candidate: dict[str, Any]) -> float | None:
    direct = _candidate_numeric(
        candidate,
        "liquidity_reference",
        "session_dollar_volume",
        "average_dollar_volume",
        "avg_dollar_volume",
        "average_daily_dollar_volume",
        "dollar_volume",
    )
    if direct is not None and direct > 0:
        return float(direct)
    volume = _candidate_numeric(candidate, "average_volume", "avg_volume", "volume")
    price = _candidate_numeric(candidate, "live_price", "close", "current_underlying_price")
    if volume is not None and price is not None and volume > 0 and price > 0:
        return float(volume * price)
    return None


def _candidate_expected_edge_bps(candidate: dict[str, Any]) -> float | None:
    direct = _candidate_numeric(
        candidate,
        "transaction_cost_adjusted_expected_edge_bps",
        "accuracy_calibrated_expected_edge_bps",
        "expected_edge_bps",
        "edge_bps",
        "forecast_edge_bps",
        "expected_move_bps",
    )
    if direct is not None and direct > 0:
        return abs(float(direct))
    raw_move = _candidate_numeric(candidate, "expected_move", "technical_expected_move")
    if raw_move is not None and raw_move != 0:
        return abs(float(raw_move) * 10000.0 if abs(float(raw_move)) < 1.0 else float(raw_move))
    return None


def _candidate_estimated_cost_bps(candidate: dict[str, Any], settings_state: dict[str, Any]) -> float:
    direct = _candidate_numeric(
        candidate,
        "transaction_cost_adjusted_estimated_cost_bps",
        "estimated_cost_bps",
        "expected_cost_bps",
    )
    if direct is not None and direct >= 0:
        return float(direct)
    order_type = str(settings_state.get("order_type") or "limit").strip().lower()
    base_cost = float(
        settings_state.get("market_slippage_bps" if order_type == "market" else "limit_slippage_bps")
        or (20.0 if order_type == "market" else 10.0)
    )
    spread = _candidate_spread_bps(candidate)
    return float(base_cost + ((spread or 0.0) / 2.0))


def _candidate_edge_to_cost_ratio(candidate: dict[str, Any], settings_state: dict[str, Any]) -> float | None:
    direct = _candidate_numeric(candidate, "transaction_cost_adjusted_edge_to_cost_ratio", "edge_to_cost_ratio")
    if direct is not None and direct > 0:
        return float(direct)
    edge = _candidate_expected_edge_bps(candidate)
    cost = _candidate_estimated_cost_bps(candidate, settings_state)
    if edge is not None and cost > 0:
        return float(edge / cost)
    return None


_TRADE_SELECTION_EDGE_MAX_UPRANK = 5.0
_TRADE_SELECTION_EDGE_MAX_DOWNRANK = -10.0
_TRADE_SELECTION_EDGE_MAX_SPREAD_BPS = 35.0
_TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS = 120.0
_REALTIME_ALPHA_OPS_MAX_UPRANK = 3.0
_REALTIME_ALPHA_OPS_MAX_DOWNRANK = -6.0
_ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_UPRANK = 2.5
_ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_DOWNRANK = -7.0
_PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_UPRANK = 2.0
_PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_DOWNRANK = -8.0
_INSTITUTIONAL_OPERATING_EDGE_MAX_UPRANK = 1.25
_INSTITUTIONAL_OPERATING_EDGE_MAX_DOWNRANK = -9.0
_AGAINST_MARKET_PROXY_MAX_UPRANK = 2.0
_AGAINST_MARKET_PROXY_MAX_DOWNRANK = -6.0
_MARKET_POSSIBILITY_ENGINE_MAX_UPRANK = 4.0
_MARKET_POSSIBILITY_ENGINE_MAX_DOWNRANK = -8.0
_MARKET_POSSIBILITY_MODEL_VERSION = "market_possibility_engine_v1"
_MARKET_POSSIBILITY_SCENARIO_TYPES = (
    "trend_continuation",
    "failed_breakout",
    "vwap_reclaim",
    "vwap_rejection",
    "range_chop",
    "risk_off_acceleration",
    "reversal",
    "volatility_expansion",
    "liquidity_deterioration",
)
_MARKET_POSSIBILITY_HARD_BLOCKERS = {
    "cooldown_active",
    "kill_switch_active",
    "loss_lock",
    "target_lock",
    "route_block",
    "reconciliation_block",
    "daily_risk_gate",
    "stale_quote",
    "wide_spread",
    "spread_too_wide",
    "open_heat",
    "sector_heat",
    "correlation_heat",
}


def _trade_selection_edge_overlay(candidate: dict[str, Any], *, settings_state: dict[str, Any] | None = None) -> dict[str, Any]:
    settings = dict(settings_state or {})
    opportunity_score = _candidate_numeric(candidate, "opportunity_score") or 0.0
    stage_one_score = _candidate_numeric(candidate, "stage_one_priority_score", "stage_one_score") or 0.0
    deep_score = _candidate_numeric(candidate, "deep_score", "setup_score", "ranking_score") or 0.0
    edge_to_cost = _candidate_edge_to_cost_ratio(candidate, settings) if settings else _candidate_numeric(candidate, "edge_to_cost_ratio")
    quote_age = _candidate_numeric(candidate, "quote_age_seconds")
    quote_freshness = candidate.get("quote_freshness") if isinstance(candidate.get("quote_freshness"), dict) else {}
    if quote_age is None:
        quote_age = _candidate_numeric(quote_freshness, "age_seconds")
    spread_bps = _candidate_spread_bps(candidate)
    max_spread_bps = float(settings.get("max_spread_bps_for_opportunity") or _TRADE_SELECTION_EDGE_MAX_SPREAD_BPS)
    review = candidate.get("ai_evidence_review") if isinstance(candidate.get("ai_evidence_review"), dict) else {}
    verdict = str(review.get("verdict") or "").strip().lower()
    ai_score = (
        100.0
        if verdict == "approve_evidence"
        else 70.0
        if verdict == "size_down"
        else 55.0
        if verdict == "wait_for_confirmation"
        else 25.0
        if verdict == "reject_evidence"
        else 50.0
    )
    freshness_score = (
        65.0
        if quote_age is None
        else 100.0
        if quote_age <= 30.0
        else 80.0
        if quote_age <= _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS
        else 15.0
    )
    spread_score = (
        65.0
        if spread_bps is None
        else 100.0
        if spread_bps <= max_spread_bps
        else 60.0
        if spread_bps <= max_spread_bps * 1.75
        else 20.0
    )
    cost_score = (
        60.0
        if edge_to_cost is None
        else 100.0
        if edge_to_cost >= 2.0
        else 75.0
        if edge_to_cost >= 1.25
        else 35.0
    )
    has_basic_evidence = any(
        [
            opportunity_score > 0,
            stage_one_score > 0,
            deep_score > 0,
            bool(candidate.get("rapid_confirmed")),
            bool(review),
        ]
    )
    reason_codes: list[str] = []
    if opportunity_score >= float(settings.get("min_opportunity_score") or _AUTOMATION_OPPORTUNITY_SCORE_DEFAULT):
        reason_codes.append("opportunity_capture_pass")
    elif opportunity_score > 0:
        reason_codes.append("opportunity_capture_weak")
    if bool(candidate.get("rapid_confirmed")):
        reason_codes.append("rapid_confirmation_ready")
    if str(candidate.get("deep_analysis_status") or "").strip().lower() == "deep_analysis_ready":
        reason_codes.append("deep_analysis_ready")
    if verdict:
        reason_codes.append(f"ai_{verdict}")
    hard_gate_blocked = False
    if quote_age is not None and quote_age > _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS:
        hard_gate_blocked = True
        reason_codes.append("stale_quote_guard")
    if spread_bps is not None and spread_bps > max_spread_bps:
        hard_gate_blocked = True
        reason_codes.append("wide_spread_guard")
    if not has_basic_evidence:
        reason_codes.append("insufficient_basic_evidence")

    evidence_edge_score = _score_bound(
        (opportunity_score * 0.34)
        + (stage_one_score * 0.20)
        + (deep_score * 0.18)
        + (ai_score * 0.12)
        + (freshness_score * 0.08)
        + (spread_score * 0.05)
        + (cost_score * 0.03)
    )
    if not has_basic_evidence:
        adjustment = 0.0
        status = "insufficient_evidence"
    elif hard_gate_blocked:
        adjustment = max(_TRADE_SELECTION_EDGE_MAX_DOWNRANK, min(0.0, (evidence_edge_score - 55.0) / 4.0))
        status = "hard_gate_observed_no_uprank"
    elif evidence_edge_score >= 70.0:
        adjustment = min(_TRADE_SELECTION_EDGE_MAX_UPRANK, (evidence_edge_score - 70.0) / 6.0)
        status = "active_paper_ranking_input"
    elif evidence_edge_score < 55.0:
        adjustment = max(_TRADE_SELECTION_EDGE_MAX_DOWNRANK, (evidence_edge_score - 55.0) / 3.0)
        status = "active_paper_downrank"
    else:
        adjustment = 0.0
        status = "observed_no_adjustment"
    return {
        "status": SAFETY_STATE_READY,
        "usage_status": status,
        "evidence_edge_score": round(evidence_edge_score, 4),
        "priority_adjustment": round(adjustment, 4),
        "reason_codes": reason_codes,
        "max_uprank": _TRADE_SELECTION_EDGE_MAX_UPRANK,
        "max_downrank": _TRADE_SELECTION_EDGE_MAX_DOWNRANK,
        "hard_gate_observed": hard_gate_blocked,
        "hard_gates_remain_authoritative": True,
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "mutation": "paper_evidence_state",
    }


def _apply_trade_selection_edge_candidate_overlay(
    candidates: list[dict[str, Any]],
    *,
    settings_state: dict[str, Any],
) -> list[dict[str, Any]]:
    enriched: list[dict[str, Any]] = []
    for candidate in candidates:
        row = dict(candidate)
        overlay = _trade_selection_edge_overlay(row, settings_state=settings_state)
        base_portfolio_score = _candidate_numeric(row, "portfolio_score") or 0.0
        adjusted_portfolio_score = max(base_portfolio_score + float(overlay.get("priority_adjustment") or 0.0), 0.0)
        row["trade_selection_edge"] = overlay
        row["evidence_edge_score"] = overlay["evidence_edge_score"]
        row["edge_priority_adjustment"] = overlay["priority_adjustment"]
        row["edge_reason_codes"] = list(overlay.get("reason_codes") or [])
        row["edge_usage_status"] = overlay["usage_status"]
        row["edge_adjusted_portfolio_score"] = round(adjusted_portfolio_score, 4)
        enriched.append(row)
    return enriched


def _realtime_alpha_ops_overlay(candidate: dict[str, Any], *, settings_state: dict[str, Any] | None = None) -> dict[str, Any]:
    settings = dict(settings_state or {})
    opportunity_score = _candidate_numeric(candidate, "opportunity_score") or 0.0
    stage_one_score = _candidate_numeric(candidate, "stage_one_priority_score", "stage_one_score") or 0.0
    deep_score = _candidate_numeric(candidate, "deep_score", "setup_score", "ranking_score") or 0.0
    evidence_edge_score = _candidate_numeric(candidate, "evidence_edge_score") or _candidate_numeric(
        candidate.get("trade_selection_edge") if isinstance(candidate.get("trade_selection_edge"), dict) else {},
        "evidence_edge_score",
    ) or 0.0
    portfolio_score = _candidate_numeric(candidate, "edge_adjusted_portfolio_score", "portfolio_score") or 0.0
    execution_score = _candidate_numeric(candidate, "execution_score") or 0.0
    quote_age = _candidate_numeric(candidate, "quote_age_seconds")
    quote_freshness = candidate.get("quote_freshness") if isinstance(candidate.get("quote_freshness"), dict) else {}
    if quote_age is None:
        quote_age = _candidate_numeric(quote_freshness, "age_seconds")
    spread_bps = _candidate_spread_bps(candidate)
    max_spread_bps = float(settings.get("max_spread_bps_for_opportunity") or _TRADE_SELECTION_EDGE_MAX_SPREAD_BPS)
    opportunity_type = str(candidate.get("opportunity_type") or "none").strip().lower() or "none"
    time_window = str(candidate.get("opportunity_time_window") or "").strip().lower()
    blocker = str(candidate.get("blocker") or candidate.get("blocked_reason") or "").strip().lower()
    review = candidate.get("ai_evidence_review") if isinstance(candidate.get("ai_evidence_review"), dict) else {}
    verdict = str(review.get("verdict") or "").strip().lower()
    post_move = candidate.get("post_move_followup") if isinstance(candidate.get("post_move_followup"), dict) else {}
    follow_up_move = _candidate_numeric(post_move, "current_move_pct", "move_pct")
    min_opportunity_score = float(settings.get("min_opportunity_score") or _AUTOMATION_OPPORTUNITY_SCORE_DEFAULT)
    quote_fresh = quote_age is None or quote_age <= _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS
    spread_ok = spread_bps is None or spread_bps <= max_spread_bps
    has_confirmation = bool(candidate.get("rapid_confirmed")) or str(candidate.get("deep_analysis_status") or "").strip().lower() == "deep_analysis_ready"
    active_setup = opportunity_score > 0.0 or stage_one_score > 0.0 or deep_score > 0.0 or has_confirmation

    setup_state = {
        "status": "active" if active_setup else "waiting",
        "type": opportunity_type,
        "heartbeat": "fresh" if quote_fresh else "stale",
        "birth_at": candidate.get("setup_birth_at") or candidate.get("candidate_created_at") or candidate.get("evaluated_at"),
        "expiry_at": candidate.get("setup_expiry_at"),
        "invalidation_at": candidate.get("setup_invalidation_at"),
        "opportunity_window": time_window or "market_session",
        "urgency_bucket": (
            "urgent"
            if opportunity_score >= min_opportunity_score + 10.0 and has_confirmation
            else "watch"
            if opportunity_score > 0.0
            else "idle"
        ),
        "confidence_age_decay": 0.0 if quote_age is None else round(min(max(quote_age / _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS, 0.0), 1.0), 4),
        "states": {
            "opening_drive": opportunity_type in {"opening_range_breakout", "opening_drive", "breakout"} or time_window.startswith("opening"),
            "vwap_reclaim": "vwap" in opportunity_type,
            "vwap_hold": "vwap" in opportunity_type and has_confirmation,
            "pullback_continuation": "pullback" in opportunity_type or "continuation" in opportunity_type,
            "compression_break": "compression" in opportunity_type,
            "acceleration": "acceleration" in opportunity_type,
            "reversal_risk": "reversal" in opportunity_type or blocker in {"failed_breakout", "event_risk"},
            "failed_breakout": blocker == "failed_breakout" or "failed_breakout" in opportunity_type,
            "sector_confirmed": bool(candidate.get("sector_confirmed") or candidate.get("sector_confirmation")),
            "etf_confirmed": bool(candidate.get("etf_confirmed") or candidate.get("etf_confirmation")),
            "broad_market_confirmed": bool(candidate.get("market_confirmed") or candidate.get("broad_market_confirmation")),
            "relative_volume_impulse": (_candidate_numeric(candidate, "relative_volume") or 0.0) >= float(settings.get("min_breakout_relative_volume") or 1.4),
            "liquidity_confirmed": (_candidate_liquidity(candidate) or 0.0) > 0.0,
            "spread_confirmed": spread_ok,
            "quote_fresh": quote_fresh,
        },
    }
    threshold_state = {
        "status": "pass" if opportunity_score >= min_opportunity_score else "weak" if opportunity_score > 0.0 else "waiting",
        "symbol_baseline": {
            "score": min_opportunity_score,
            "volume": settings.get("min_breakout_relative_volume") or 1.4,
            "spread_bps": max_spread_bps,
            "volatility": "dynamic_from_scan",
        },
        "time_window": time_window or "market_session",
        "threshold": min_opportunity_score,
        "drift": round(opportunity_score - min_opportunity_score, 4),
        "confidence": _score_bound(50.0 + (opportunity_score - min_opportunity_score) * 1.5),
        "fallback": "global_default",
    }
    regime_fit_score = _score_bound(
        (opportunity_score * 0.35)
        + (stage_one_score * 0.20)
        + (deep_score * 0.15)
        + (100.0 if has_confirmation else 35.0) * 0.10
        + (100.0 if quote_fresh else 15.0) * 0.10
        + (100.0 if spread_ok else 20.0) * 0.10
    )
    allocator_fit_score = _score_bound((portfolio_score * 0.55) + (execution_score * 0.25) + (evidence_edge_score * 0.20))
    memory_adjustment = 0.0
    if follow_up_move is not None and follow_up_move >= 1.0 and blocker not in {"stale_quote", "spread_too_wide", "wide_spread_guard"}:
        memory_adjustment = 1.5
    elif blocker in {"failed_breakout", "event_risk"}:
        memory_adjustment = -1.5
    hard_gate_blocked = False
    reason_codes: list[str] = []
    if not quote_fresh:
        hard_gate_blocked = True
        reason_codes.append("stale_quote_guard")
    if not spread_ok:
        hard_gate_blocked = True
        reason_codes.append("wide_spread_guard")
    if blocker in {"cooldown_active", "kill_switch_active", "loss_lock", "target_lock", "route_block", "reconciliation_block"}:
        hard_gate_blocked = True
        reason_codes.append(f"{blocker}_guard")
    if active_setup:
        reason_codes.append("active_setup_state")
    if has_confirmation:
        reason_codes.append("confirmation_available")
    if threshold_state["status"] == "pass":
        reason_codes.append("adaptive_threshold_pass")
    if verdict:
        reason_codes.append(f"ai_{verdict}")
    realtime_alpha_score = _score_bound(
        (evidence_edge_score * 0.28)
        + (regime_fit_score * 0.22)
        + (allocator_fit_score * 0.18)
        + (opportunity_score * 0.16)
        + (threshold_state["confidence"] * 0.10)
        + ((memory_adjustment + 6.0) / 9.0 * 100.0 * 0.06)
    )
    if not active_setup:
        adjustment = 0.0
        usage_status = "waiting_for_setup"
        reason_codes.append("no_active_setup")
    elif hard_gate_blocked:
        adjustment = max(_REALTIME_ALPHA_OPS_MAX_DOWNRANK, min(0.0, (realtime_alpha_score - 60.0) / 7.0))
        usage_status = "hard_gate_observed_no_uprank"
    elif realtime_alpha_score >= 72.0:
        adjustment = min(_REALTIME_ALPHA_OPS_MAX_UPRANK, (realtime_alpha_score - 72.0) / 8.0)
        usage_status = "active_paper_ranking_input"
    elif realtime_alpha_score < 56.0:
        adjustment = max(_REALTIME_ALPHA_OPS_MAX_DOWNRANK, (realtime_alpha_score - 56.0) / 6.0)
        usage_status = "active_paper_downrank"
    else:
        adjustment = 0.0
        usage_status = "observed_no_adjustment"
    return {
        "status": SAFETY_STATE_READY,
        "usage_status": usage_status,
        "realtime_alpha_score": round(realtime_alpha_score, 4),
        "priority_adjustment": round(adjustment, 4),
        "realtime_setup_state": setup_state,
        "adaptive_threshold_state": threshold_state,
        "regime_fit_score": round(regime_fit_score, 4),
        "memory_adjustment": round(memory_adjustment, 4),
        "allocator_fit_score": round(allocator_fit_score, 4),
        "reason_codes": reason_codes,
        "max_uprank": _REALTIME_ALPHA_OPS_MAX_UPRANK,
        "max_downrank": _REALTIME_ALPHA_OPS_MAX_DOWNRANK,
        "hard_gate_observed": hard_gate_blocked,
        "hard_gates_remain_authoritative": True,
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "mutation": "paper_evidence_state",
    }


def _apply_realtime_alpha_ops_candidate_overlay(
    candidates: list[dict[str, Any]],
    *,
    settings_state: dict[str, Any],
) -> list[dict[str, Any]]:
    enriched: list[dict[str, Any]] = []
    for candidate in candidates:
        row = dict(candidate)
        overlay = _realtime_alpha_ops_overlay(row, settings_state=settings_state)
        base_score = _candidate_numeric(row, "edge_adjusted_portfolio_score", "portfolio_score") or 0.0
        adjusted_score = max(base_score + float(overlay.get("priority_adjustment") or 0.0), 0.0)
        row["realtime_alpha_ops"] = overlay
        row["realtime_setup_state"] = overlay["realtime_setup_state"]
        row["adaptive_threshold_state"] = overlay["adaptive_threshold_state"]
        row["regime_fit_score"] = overlay["regime_fit_score"]
        row["memory_adjustment"] = overlay["memory_adjustment"]
        row["allocator_fit_score"] = overlay["allocator_fit_score"]
        row["realtime_alpha_reason_codes"] = list(overlay.get("reason_codes") or [])
        row["realtime_alpha_priority_adjustment"] = overlay["priority_adjustment"]
        row["realtime_alpha_score"] = overlay["realtime_alpha_score"]
        row["realtime_alpha_usage_status"] = overlay["usage_status"]
        row["realtime_alpha_adjusted_portfolio_score"] = round(adjusted_score, 4)
        enriched.append(row)
    return enriched


def _adaptive_execution_intelligence_overlay(
    candidate: dict[str, Any],
    *,
    settings_state: dict[str, Any] | None = None,
) -> dict[str, Any]:
    settings = dict(settings_state or {})
    trade_selection_edge = candidate.get("trade_selection_edge") if isinstance(candidate.get("trade_selection_edge"), dict) else {}
    realtime_alpha_ops = candidate.get("realtime_alpha_ops") if isinstance(candidate.get("realtime_alpha_ops"), dict) else {}
    opportunity_score = _candidate_numeric(candidate, "opportunity_score") or 0.0
    execution_score = _candidate_numeric(candidate, "execution_score", "ranking_score", "setup_score") or 0.0
    evidence_edge_score = _candidate_numeric(candidate, "evidence_edge_score") or _candidate_numeric(trade_selection_edge, "evidence_edge_score") or 0.0
    realtime_alpha_score = _candidate_numeric(candidate, "realtime_alpha_score") or _candidate_numeric(realtime_alpha_ops, "realtime_alpha_score") or 0.0
    allocator_fit_score = _candidate_numeric(candidate, "allocator_fit_score") or _candidate_numeric(realtime_alpha_ops, "allocator_fit_score") or 0.0
    quote_age = _candidate_numeric(candidate, "quote_age_seconds")
    quote_freshness = candidate.get("quote_freshness") if isinstance(candidate.get("quote_freshness"), dict) else {}
    if quote_age is None:
        quote_age = _candidate_numeric(quote_freshness, "age_seconds")
    spread_bps = _candidate_spread_bps(candidate)
    max_spread_bps = float(settings.get("max_spread_bps_for_opportunity") or _TRADE_SELECTION_EDGE_MAX_SPREAD_BPS)
    edge_to_cost = _candidate_edge_to_cost_ratio(candidate, settings) if settings else _candidate_numeric(candidate, "edge_to_cost_ratio")
    risk_reward = _candidate_numeric(candidate, "risk_reward_ratio", "reward_to_risk", "target_to_stop_ratio")
    has_confirmation = bool(candidate.get("rapid_confirmed")) or str(candidate.get("deep_analysis_status") or "").strip().lower() == "deep_analysis_ready"
    has_basic_evidence = any(
        [
            opportunity_score > 0.0,
            execution_score > 0.0,
            evidence_edge_score > 0.0,
            realtime_alpha_score > 0.0,
            has_confirmation,
        ]
    )
    quote_fresh = quote_age is None or quote_age <= _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS
    spread_ok = spread_bps is None or spread_bps <= max_spread_bps
    blocker = str(candidate.get("blocker") or candidate.get("blocked_reason") or candidate.get("risk_blocker") or "").strip().lower()
    hard_gate_blockers = {
        "cooldown_active",
        "kill_switch_active",
        "loss_lock",
        "target_lock",
        "route_block",
        "reconciliation_block",
        "daily_risk_gate",
        "stale_quote",
        "wide_spread",
        "spread_too_wide",
    }
    hard_gate_blocked = False
    reason_codes: list[str] = []
    if not quote_fresh:
        hard_gate_blocked = True
        reason_codes.append("stale_quote_guard")
    if not spread_ok:
        hard_gate_blocked = True
        reason_codes.append("wide_spread_guard")
    if blocker in hard_gate_blockers:
        hard_gate_blocked = True
        reason_codes.append(f"{blocker}_guard")
    if has_confirmation:
        reason_codes.append("confirmation_available")
    if evidence_edge_score > 0.0:
        reason_codes.append("trade_selection_edge_available")
    if realtime_alpha_score > 0.0:
        reason_codes.append("realtime_alpha_available")
    if execution_score >= 60.0:
        reason_codes.append("execution_score_pass")
    if edge_to_cost is not None and edge_to_cost >= 1.25:
        reason_codes.append("edge_survives_estimated_cost")
    if risk_reward is not None and risk_reward >= 1.5:
        reason_codes.append("reward_risk_fit")
    if not has_basic_evidence:
        reason_codes.append("insufficient_execution_evidence")

    freshness_score = 65.0 if quote_age is None else 100.0 if quote_age <= 30.0 else 80.0 if quote_fresh else 15.0
    spread_score = 65.0 if spread_bps is None else 100.0 if spread_ok else 35.0
    edge_cost_score = 60.0 if edge_to_cost is None else 100.0 if edge_to_cost >= 2.0 else 76.0 if edge_to_cost >= 1.25 else 35.0
    reward_risk_fit_score = 60.0 if risk_reward is None else 100.0 if risk_reward >= 2.0 else 78.0 if risk_reward >= 1.5 else 40.0
    entry_timing_score = _score_bound(
        (opportunity_score * 0.30)
        + (realtime_alpha_score * 0.25)
        + (freshness_score * 0.20)
        + (spread_score * 0.15)
        + ((100.0 if has_confirmation else 35.0) * 0.10)
    )
    exit_timing_score = _score_bound(
        (reward_risk_fit_score * 0.50)
        + (execution_score * 0.20)
        + (allocator_fit_score * 0.15)
        + ((100.0 if candidate.get("target_price") or candidate.get("take_profit_price") else 55.0) * 0.075)
        + ((100.0 if candidate.get("stop_price") or candidate.get("stop_loss_price") else 55.0) * 0.075)
    )
    sizing_confidence_score = _score_bound(
        (allocator_fit_score * 0.35)
        + (execution_score * 0.25)
        + (evidence_edge_score * 0.20)
        + (spread_score * 0.10)
        + (freshness_score * 0.10)
    )
    slippage_risk_score = _score_bound((spread_score * 0.50) + (edge_cost_score * 0.30) + (freshness_score * 0.20))
    adaptive_execution_score = _score_bound(
        (entry_timing_score * 0.25)
        + (exit_timing_score * 0.18)
        + (sizing_confidence_score * 0.18)
        + (slippage_risk_score * 0.16)
        + (reward_risk_fit_score * 0.13)
        + (realtime_alpha_score * 0.10)
    )
    if not has_basic_evidence:
        adjustment = 0.0
        usage_status = "waiting_for_execution_evidence"
    elif hard_gate_blocked:
        adjustment = max(_ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_DOWNRANK, min(0.0, (adaptive_execution_score - 62.0) / 8.0))
        usage_status = "hard_gate_observed_no_uprank"
    elif adaptive_execution_score >= 74.0:
        adjustment = min(_ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_UPRANK, (adaptive_execution_score - 74.0) / 10.0)
        usage_status = "active_paper_ranking_and_allocator_input"
    elif adaptive_execution_score < 58.0:
        adjustment = max(_ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_DOWNRANK, (adaptive_execution_score - 58.0) / 5.0)
        usage_status = "active_paper_downrank"
    else:
        adjustment = 0.0
        usage_status = "observed_no_adjustment"
    return {
        "status": SAFETY_STATE_READY,
        "usage_status": usage_status,
        "adaptive_execution_score": round(adaptive_execution_score, 4),
        "priority_adjustment": round(adjustment, 4),
        "entry_timing_score": round(entry_timing_score, 4),
        "exit_timing_score": round(exit_timing_score, 4),
        "sizing_confidence_score": round(sizing_confidence_score, 4),
        "slippage_risk_score": round(slippage_risk_score, 4),
        "reward_risk_fit_score": round(reward_risk_fit_score, 4),
        "reason_codes": reason_codes,
        "max_uprank": _ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_UPRANK,
        "max_downrank": _ADAPTIVE_EXECUTION_INTELLIGENCE_MAX_DOWNRANK,
        "hard_gate_observed": hard_gate_blocked,
        "hard_gates_remain_authoritative": True,
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "mutation": "paper_evidence_state",
    }


def _apply_adaptive_execution_intelligence_candidate_overlay(
    candidates: list[dict[str, Any]],
    *,
    settings_state: dict[str, Any],
) -> list[dict[str, Any]]:
    enriched: list[dict[str, Any]] = []
    for candidate in candidates:
        row = dict(candidate)
        overlay = _adaptive_execution_intelligence_overlay(row, settings_state=settings_state)
        base_score = _candidate_numeric(
            row,
            "realtime_alpha_adjusted_portfolio_score",
            "edge_adjusted_portfolio_score",
            "portfolio_score",
        ) or 0.0
        adjusted_score = max(base_score + float(overlay.get("priority_adjustment") or 0.0), 0.0)
        row["adaptive_execution_intelligence"] = overlay
        row["adaptive_execution_score"] = overlay["adaptive_execution_score"]
        row["entry_timing_score"] = overlay["entry_timing_score"]
        row["exit_timing_score"] = overlay["exit_timing_score"]
        row["sizing_confidence_score"] = overlay["sizing_confidence_score"]
        row["slippage_risk_score"] = overlay["slippage_risk_score"]
        row["reward_risk_fit_score"] = overlay["reward_risk_fit_score"]
        row["execution_learning_reason_codes"] = list(overlay.get("reason_codes") or [])
        row["adaptive_execution_priority_adjustment"] = overlay["priority_adjustment"]
        row["adaptive_execution_usage_status"] = overlay["usage_status"]
        row["adaptive_execution_adjusted_portfolio_score"] = round(adjusted_score, 4)
        enriched.append(row)
    return enriched


def _portfolio_outcome_intelligence_overlay(
    candidate: dict[str, Any],
    *,
    settings_state: dict[str, Any] | None = None,
) -> dict[str, Any]:
    settings = dict(settings_state or {})
    trade_selection_edge = candidate.get("trade_selection_edge") if isinstance(candidate.get("trade_selection_edge"), dict) else {}
    realtime_alpha_ops = candidate.get("realtime_alpha_ops") if isinstance(candidate.get("realtime_alpha_ops"), dict) else {}
    adaptive_execution = (
        candidate.get("adaptive_execution_intelligence")
        if isinstance(candidate.get("adaptive_execution_intelligence"), dict)
        else {}
    )
    opportunity_score = _candidate_numeric(candidate, "opportunity_score") or 0.0
    execution_score = _candidate_numeric(candidate, "execution_score", "ranking_score", "setup_score") or 0.0
    evidence_edge_score = _candidate_numeric(candidate, "evidence_edge_score") or _candidate_numeric(trade_selection_edge, "evidence_edge_score") or 0.0
    realtime_alpha_score = _candidate_numeric(candidate, "realtime_alpha_score") or _candidate_numeric(realtime_alpha_ops, "realtime_alpha_score") or 0.0
    adaptive_execution_score = _candidate_numeric(candidate, "adaptive_execution_score") or _candidate_numeric(adaptive_execution, "adaptive_execution_score") or 0.0
    allocator_fit_score = _candidate_numeric(candidate, "allocator_fit_score") or _candidate_numeric(realtime_alpha_ops, "allocator_fit_score") or 0.0
    slippage_risk_score = _candidate_numeric(candidate, "slippage_risk_score") or _candidate_numeric(adaptive_execution, "slippage_risk_score") or 0.0
    reward_risk_fit_score = _candidate_numeric(candidate, "reward_risk_fit_score") or _candidate_numeric(adaptive_execution, "reward_risk_fit_score") or 0.0
    quote_age = _candidate_numeric(candidate, "quote_age_seconds")
    quote_freshness = candidate.get("quote_freshness") if isinstance(candidate.get("quote_freshness"), dict) else {}
    if quote_age is None:
        quote_age = _candidate_numeric(quote_freshness, "age_seconds")
    spread_bps = _candidate_spread_bps(candidate)
    max_spread_bps = float(settings.get("max_spread_bps_for_opportunity") or _TRADE_SELECTION_EDGE_MAX_SPREAD_BPS)
    edge_to_cost = _candidate_edge_to_cost_ratio(candidate, settings) if settings else _candidate_numeric(candidate, "edge_to_cost_ratio")
    risk_reward = _candidate_numeric(candidate, "risk_reward_ratio", "reward_to_risk", "target_to_stop_ratio")
    portfolio_score = _candidate_numeric(candidate, "portfolio_score") or 0.0
    correlation_bucket = str(
        candidate.get("proxy_correlation_bucket") or candidate.get("correlation_bucket") or candidate.get("sector") or ""
    ).strip()
    blocker = str(candidate.get("blocker") or candidate.get("blocked_reason") or candidate.get("risk_blocker") or "").strip().lower()
    hard_gate_blockers = {
        "cooldown_active",
        "kill_switch_active",
        "loss_lock",
        "target_lock",
        "route_block",
        "reconciliation_block",
        "daily_risk_gate",
        "stale_quote",
        "wide_spread",
        "spread_too_wide",
    }
    quote_fresh = quote_age is None or quote_age <= _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS
    spread_ok = spread_bps is None or spread_bps <= max_spread_bps
    hard_gate_blocked = False
    reason_codes: list[str] = []
    if not quote_fresh:
        hard_gate_blocked = True
        reason_codes.append("stale_quote_guard")
    if not spread_ok:
        hard_gate_blocked = True
        reason_codes.append("wide_spread_guard")
    if blocker in hard_gate_blockers:
        hard_gate_blocked = True
        reason_codes.append(f"{blocker}_guard")
    if correlation_bucket:
        reason_codes.append("correlation_bucket_available")
    if adaptive_execution_score > 0.0:
        reason_codes.append("adaptive_execution_available")
    if allocator_fit_score >= 60.0:
        reason_codes.append("allocator_fit_available")
    if reward_risk_fit_score >= 70.0 or (risk_reward is not None and risk_reward >= 1.5):
        reason_codes.append("portfolio_reward_risk_fit")
    if edge_to_cost is not None and edge_to_cost >= 1.25:
        reason_codes.append("capital_efficiency_pass")

    has_basic_evidence = any(
        [
            opportunity_score > 0.0,
            execution_score > 0.0,
            evidence_edge_score > 0.0,
            realtime_alpha_score > 0.0,
            adaptive_execution_score > 0.0,
            allocator_fit_score > 0.0,
        ]
    )
    if not has_basic_evidence:
        reason_codes.append("insufficient_portfolio_outcome_evidence")

    freshness_score = 65.0 if quote_age is None else 100.0 if quote_age <= 30.0 else 80.0 if quote_fresh else 15.0
    spread_score = 65.0 if spread_bps is None else 100.0 if spread_ok else 35.0
    edge_cost_score = 60.0 if edge_to_cost is None else 100.0 if edge_to_cost >= 2.0 else 76.0 if edge_to_cost >= 1.25 else 35.0
    reward_score = reward_risk_fit_score or (
        60.0 if risk_reward is None else 100.0 if risk_reward >= 2.0 else 78.0 if risk_reward >= 1.5 else 40.0
    )
    drawdown_resilience_score = _score_bound(
        (reward_score * 0.30)
        + (slippage_risk_score * 0.20)
        + (freshness_score * 0.20)
        + (spread_score * 0.15)
        + ((100.0 if not hard_gate_blocked else 30.0) * 0.15)
    )
    portfolio_risk_fit_score = _score_bound(
        (allocator_fit_score * 0.28)
        + (reward_score * 0.24)
        + (spread_score * 0.18)
        + (freshness_score * 0.15)
        + (adaptive_execution_score * 0.15)
    )
    capital_efficiency_score = _score_bound(
        (edge_cost_score * 0.32)
        + (evidence_edge_score * 0.20)
        + (adaptive_execution_score * 0.18)
        + (opportunity_score * 0.15)
        + (portfolio_score * 0.15)
    )
    outcome_memory_score = _score_bound(
        (adaptive_execution_score * 0.30)
        + (realtime_alpha_score * 0.20)
        + (evidence_edge_score * 0.18)
        + (execution_score * 0.16)
        + (reward_score * 0.16)
    )
    portfolio_outcome_score = _score_bound(
        (portfolio_risk_fit_score * 0.28)
        + (drawdown_resilience_score * 0.22)
        + (capital_efficiency_score * 0.22)
        + (outcome_memory_score * 0.18)
        + (allocator_fit_score * 0.10)
    )
    if not has_basic_evidence:
        adjustment = 0.0
        usage_status = "waiting_for_portfolio_outcome_evidence"
    elif hard_gate_blocked:
        adjustment = max(_PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_DOWNRANK, min(0.0, (portfolio_outcome_score - 60.0) / 8.0))
        usage_status = "hard_gate_observed_no_uprank"
    elif portfolio_outcome_score >= 76.0:
        adjustment = min(_PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_UPRANK, (portfolio_outcome_score - 76.0) / 12.0)
        usage_status = "active_paper_portfolio_ranking_and_allocator_input"
    elif portfolio_outcome_score < 56.0:
        adjustment = max(_PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_DOWNRANK, (portfolio_outcome_score - 56.0) / 5.0)
        usage_status = "active_paper_portfolio_downrank"
    else:
        adjustment = 0.0
        usage_status = "observed_no_adjustment"
    return {
        "status": SAFETY_STATE_READY,
        "usage_status": usage_status,
        "portfolio_outcome_score": round(portfolio_outcome_score, 4),
        "portfolio_risk_fit_score": round(portfolio_risk_fit_score, 4),
        "drawdown_resilience_score": round(drawdown_resilience_score, 4),
        "capital_efficiency_score": round(capital_efficiency_score, 4),
        "outcome_memory_score": round(outcome_memory_score, 4),
        "priority_adjustment": round(adjustment, 4),
        "reason_codes": reason_codes,
        "max_uprank": _PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_UPRANK,
        "max_downrank": _PORTFOLIO_OUTCOME_INTELLIGENCE_MAX_DOWNRANK,
        "hard_gate_observed": hard_gate_blocked,
        "hard_gates_remain_authoritative": True,
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "mutation": "paper_evidence_state",
    }


def _apply_portfolio_outcome_intelligence_candidate_overlay(
    candidates: list[dict[str, Any]],
    *,
    settings_state: dict[str, Any],
) -> list[dict[str, Any]]:
    enriched: list[dict[str, Any]] = []
    for candidate in candidates:
        row = dict(candidate)
        overlay = _portfolio_outcome_intelligence_overlay(row, settings_state=settings_state)
        base_score = _candidate_numeric(
            row,
            "adaptive_execution_adjusted_portfolio_score",
            "realtime_alpha_adjusted_portfolio_score",
            "edge_adjusted_portfolio_score",
            "portfolio_score",
        ) or 0.0
        adjusted_score = max(base_score + float(overlay.get("priority_adjustment") or 0.0), 0.0)
        row["portfolio_outcome_intelligence"] = overlay
        row["portfolio_outcome_score"] = overlay["portfolio_outcome_score"]
        row["portfolio_risk_fit_score"] = overlay["portfolio_risk_fit_score"]
        row["drawdown_resilience_score"] = overlay["drawdown_resilience_score"]
        row["capital_efficiency_score"] = overlay["capital_efficiency_score"]
        row["outcome_memory_score"] = overlay["outcome_memory_score"]
        row["portfolio_learning_reason_codes"] = list(overlay.get("reason_codes") or [])
        row["portfolio_outcome_priority_adjustment"] = overlay["priority_adjustment"]
        row["portfolio_outcome_usage_status"] = overlay["usage_status"]
        row["portfolio_outcome_adjusted_portfolio_score"] = round(adjusted_score, 4)
        enriched.append(row)
    return enriched


