    edge_cost_score = 60.0 if edge_to_cost is None else 100.0 if edge_to_cost >= 2.0 else 76.0 if edge_to_cost >= 1.25 else 35.0
    data_integrity_score = _score_bound((freshness_score * 0.45) + (spread_score * 0.35) + (edge_cost_score * 0.20))
    operational_resilience_score = _score_bound(
        (drawdown_resilience_score * 0.30)
        + (portfolio_risk_fit_score * 0.24)
        + (data_integrity_score * 0.22)
        + ((100.0 if not hard_gate_blocked else 20.0) * 0.24)
    )
    governance_confidence_score = _score_bound(
        (portfolio_risk_fit_score * 0.30)
        + (allocator_fit_score * 0.24)
        + (capital_efficiency_score * 0.20)
        + (data_integrity_score * 0.16)
        + ((100.0 if blocker not in hard_gate_blockers else 25.0) * 0.10)
    )
    market_ops_fit_score = _score_bound(
        (portfolio_outcome_score * 0.28)
        + (adaptive_execution_score * 0.22)
        + (realtime_alpha_score * 0.18)
        + (evidence_edge_score * 0.16)
        + (opportunity_score * 0.16)
    )
