        against_status = str(item.get("against_market_usage_status") or "waiting_for_bearish_confirmation").strip().lower()
        against_market_usage_counts[against_status] = against_market_usage_counts.get(against_status, 0) + 1
        against_score = _diagnostic_float(item.get("bearish_confirmation_score"))
