        expected_value_score = _diagnostic_float(item.get("expected_value_score"))
        market_possibility_adjustment = _diagnostic_float(item.get("market_possibility_priority_adjustment"))
        if scenario_probability is not None:
            market_possibility_probabilities.append(float(scenario_probability))
        if expected_value_score is not None:
            market_possibility_expected_values.append(float(expected_value_score))
