def get_tenant_trade_automation_deep_analysis_status(
    db: Session,
    *,
    current_user: Any,
) -> dict[str, Any]:
    _assert_trade_automation_operator(current_user)
    tenant = _resolve_tenant_for_current_user(db, current_user)
    desks = _read_trade_automation_desks_store(tenant)
    by_desk = {
        desk_key: _build_trade_automation_deep_analysis_status(tenant_id=tenant.id, desk_key=desk_key)
        for desk_key in desks
    }
    overall = _build_trade_automation_deep_analysis_status(tenant_id=tenant.id)
    return serialize_value(
        {
            **overall,
            "tenant_id": tenant.id,
            "by_desk": by_desk,
            "config": {
                "max_workers": _deep_analysis_max_workers(),
                "timeout_seconds": _deep_analysis_timeout_seconds(),
                "default_cache_ttl_seconds": _deep_analysis_ttl_seconds("intraday_momentum"),
                "swing_cache_ttl_seconds": _deep_analysis_ttl_seconds("swing_position"),
                "macro_cache_ttl_seconds": _deep_analysis_ttl_seconds("macro"),
                "circuit_breaker_seconds": _deep_analysis_circuit_breaker_seconds(),
            },
        }
    )


def get_tenant_trade_automation_ai_evidence_review_status(
    db: Session,
    *,
    current_user: Any,
) -> dict[str, Any]:
    _assert_trade_automation_operator(current_user)
    tenant = _resolve_tenant_for_current_user(db, current_user)
    state = _read_trade_automation_state(tenant, profile_key=_AUTOMATION_PERSONAL_PAPER_PROFILE)
    settings_state = dict(state.get("settings") or {})
    ai_settings = automation_ai_review_service.normalize_ai_review_settings(settings_state)
    runtime_state = dict(state.get("runtime") or {})
    diagnostics = dict(runtime_state.get("last_candidate_diagnostics") or {})
    summary = dict(diagnostics.get("summary") or {})
    ai_summary = dict(summary.get("ai_evidence_review") or {})
    candidate_rows = [dict(item) for item in list(diagnostics.get("candidates") or []) if isinstance(item, dict)]
    review_rows = [dict((item.get("ai_evidence_review") or {})) for item in candidate_rows]
    ai_report = automation_ai_review_service.build_ai_evidence_review_report(
        review_rows,
        candidates=candidate_rows,
        now=_utc_now(),
    )
    missed_review = dict(summary.get("missed_trade_ai_review") or {}) or automation_ai_review_service.build_missed_trade_ai_review(
        candidate_rows,
        now=_utc_now(),
    )
    last_candidate = dict(runtime_state.get("last_candidate") or {})
    last_candidate_review = dict(last_candidate.get("ai_evidence_review") or {})
    return serialize_value(
        {
            "status": "enabled" if ai_settings["ai_evidence_review_enabled"] else "disabled",
            "tenant_id": tenant.id,
            "tenant_slug": tenant.slug,
            "mode": ai_settings["ai_evidence_review_mode"],
            "settings": {
                "ai_evidence_review_enabled": ai_settings["ai_evidence_review_enabled"],
                "ai_evidence_review_mode": ai_settings["ai_evidence_review_mode"],
                "ai_evidence_min_confidence": ai_settings["ai_evidence_min_confidence"],
                "ai_evidence_max_candidates_per_cycle": ai_settings[
                    "ai_evidence_max_candidates_per_cycle"
                ],
            },
            "last_diagnostics": {
                "evaluated_at": diagnostics.get("evaluated_at"),
                "source": diagnostics.get("source"),
                "reviewed_count": ai_summary.get("reviewed_count", 0),
                "approved_count": ai_summary.get("approved_count", 0),
                "verdict_counts": ai_summary.get("verdict_counts") or {},
                "status_counts": ai_summary.get("status_counts") or {},
                "reason_code_counts": ai_summary.get("reason_code_counts") or ai_report.get("reason_code_counts") or {},
                "evidence_incomplete_buckets": ai_summary.get("evidence_incomplete_buckets")
                or ai_report.get("evidence_incomplete_buckets")
                or {},
            },
            "report": ai_report,
            "missed_trade_review": missed_review,
            "last_candidate_review": last_candidate_review,
            "safety": {
                "paper_route_only": True,
                "can_override_risk_gates": False,
                "can_submit_orders": False,
                "final_authority": "strategy_and_risk_gates",
            },
            "next_action": (
                "AI evidence referee is reviewing candidate evidence in shadow mode."
                if ai_settings["ai_evidence_review_enabled"]
                and ai_settings["ai_evidence_review_mode"] == "shadow_review"
                else "AI evidence referee can down-rank or block paper candidates, but final gates still decide."
                if ai_settings["ai_evidence_review_enabled"]
                else "Enable AI evidence review to annotate candidate diagnostics."
            ),
        }
    )


_MARKET_OPS_REPORT_ROOT = Path("runtime-exports") / "market-days"
_MARKET_WATCHDOG_REPORT_ROOT = Path("runtime-exports") / "market-watchdog"
_CONTINUOUS_OPS_REPORT_ROOT = Path("runtime-exports") / "continuous-ops"
_CONTINUOUS_OPS_LATEST_PATH = _CONTINUOUS_OPS_REPORT_ROOT / "latest.json"
_EVIDENCE_MILLION_TARGET_COUNT = 100_000_000
_EVIDENCE_RUNTIME_EXPORT_ROOT = Path(__file__).resolve().parents[2] / "runtime-exports"
_EVIDENCE_MILLION_STATE_ROOT = _EVIDENCE_RUNTIME_EXPORT_ROOT / "evidence-million"
_EVIDENCE_MILLION_PROGRESS_PATH = _EVIDENCE_MILLION_STATE_ROOT / "progress.json"
_EVIDENCE_ACCELERATOR_ROOT = _EVIDENCE_RUNTIME_EXPORT_ROOT / "evidence-accelerator"
_SIMULATION_EVIDENCE_ROOT = _EVIDENCE_RUNTIME_EXPORT_ROOT / "simulation-evidence"
_MARKET_OPS_STATE_LABELS = {
    SAFETY_STATE_READY: ("Ready", "positive"),
    SAFETY_STATE_DEGRADED: ("Needs attention", "warning"),
    SAFETY_STATE_BLOCKED: ("Blocked", "negative"),
    SAFETY_STATE_KILLED: ("Killed", "negative"),
}
_MARKET_WATCHDOG_STATE_LABELS = {
    "ready": ("Ready", "positive"),
    "watching": ("Watching", "positive"),
    "degraded": ("Needs attention", "warning"),
    "blocked": ("Blocked", "negative"),
    "killed": ("Killed", "negative"),
}


def _market_ops_safe_int(value: Any, default: int = 0) -> int:
    try:
        return int(value or default)
    except (TypeError, ValueError):
        return default


def _market_ops_read_json_file(path: Path) -> dict[str, Any]:
    try:
        if not path.exists():
            return {}
        payload = json.loads(path.read_text(encoding="utf-8-sig"))
        return dict(payload) if isinstance(payload, dict) else {}
    except (OSError, json.JSONDecodeError):
        return {}


def _market_ops_count_jsonl_lines(path: Path, *, max_lines: int | None = None) -> int:
    try:
        with path.open("r", encoding="utf-8") as handle:
            count = 0
            for count, _line in enumerate(handle, start=1):
                if max_lines is not None and count >= max_lines:
                    return count
            return count
    except OSError:
        return 0


def _market_ops_count_candidate_lifecycle_rows(tenant_slug: str, *, max_files: int = 120) -> int:
    root = Path("runtime-exports") / "candidate-lifecycle"
    if not root.exists():
        return 0
    try:
        files = sorted(
            root.glob(f"*/{tenant_slug}.jsonl"),
            key=lambda item: item.stat().st_mtime,
            reverse=True,
        )[:max_files]
    except OSError:
        files = []
    return sum(_market_ops_count_jsonl_lines(path) for path in files)


def _market_ops_event_id(*parts: Any) -> str:
    seed = "|".join(str(part or "").strip() for part in parts)
    return hashlib.sha1(seed.encode("utf-8")).hexdigest()[:20]


def _market_ops_evidence_accelerator_snapshot(
    *,
    tenant_slug: str,
    candidate_diagnostics: dict[str, Any] | None = None,
    desks_payload: dict[str, Any] | None = None,
    components: list[dict[str, Any]] | None = None,
    now: datetime | None = None,
    persist: bool = False,
) -> dict[str, Any]:
    current = now or _utc_now()
    diagnostics = dict(candidate_diagnostics or {})
    desks_snapshot = dict(desks_payload or {})
    summary = dict(diagnostics.get("summary") or {})
    candidates = [dict(item) for item in list(diagnostics.get("candidates") or []) if isinstance(item, dict)]
    desk_items = [
        dict(item)
        for item in list(desks_snapshot.get("active_desks") or desks_snapshot.get("items") or [])
        if isinstance(item, dict)
    ]
    enabled = _normalize_bool(getattr(settings, "evidence_accelerator_enabled", True), True)
    aggressive_mode = _normalize_bool(getattr(settings, "evidence_accelerator_aggressive_mode", True), True)
    include_all_desks = _normalize_bool(getattr(settings, "evidence_accelerator_include_all_desks", True), True)
    capture_per_gate = _normalize_bool(getattr(settings, "evidence_accelerator_capture_per_gate", True), True)
    capture_per_setup = _normalize_bool(getattr(settings, "evidence_accelerator_capture_per_setup", True), True)
    capture_provider_health = _normalize_bool(getattr(settings, "evidence_accelerator_capture_provider_health", True), True)
    max_events = _normalize_int(
        getattr(settings, "evidence_accelerator_max_events_per_minute", 5000),
        5000,
        minimum=100,
        maximum=10000,
    )
    backoff_min_events = _normalize_int(
        getattr(settings, "evidence_accelerator_backoff_min_events_per_minute", 1500),
        1500,
        minimum=100,
        maximum=max_events,
    )
    backoff_duplicate_ratio = _normalize_float(
        None,
        float(getattr(settings, "evidence_accelerator_backoff_duplicate_ratio", 0.08) or 0.08),
        minimum=0.0,
        maximum=1.0,
    )
    backoff_stale_ratio = _normalize_float(
        None,
        float(getattr(settings, "evidence_accelerator_backoff_stale_ratio", 0.10) or 0.10),
        minimum=0.0,
        maximum=1.0,
    )
    write_lag_warning_ms = _normalize_int(
        getattr(settings, "evidence_accelerator_write_lag_warning_ms", 2000),
        2000,
        minimum=100,
        maximum=30000,
    )
    day = current.astimezone(_TRADE_AUTOMATION_MARKET_TZ).date().isoformat()
    target = _EVIDENCE_ACCELERATOR_ROOT / day / f"{tenant_slug}.jsonl"
    cycle_key = str(diagnostics.get("evaluated_at") or _serialize_datetime(current)).replace(":", "")
    desk_keys = list(_TRADE_AUTOMATION_ENGINE_KEYS) if include_all_desks else []
    if not desk_keys:
        desk_keys = sorted(
            {
                str(item.get("desk_key") or diagnostics.get("desk_key") or "intraday_momentum").strip().lower()
                for item in candidates
            }
        ) or ["intraday_momentum"]
    events: list[dict[str, Any]] = []
    seen_keys: set[str] = set()
    duplicate_count = 0
    stale_count = 0

    def append_event(
        *,
        event_type: str,
        ticker: str | None = None,
        desk_key: str | None = None,
        component_key: str | None = None,
        dimension: str | None = None,
        payload: dict[str, Any] | None = None,
        stale: bool = False,
    ) -> None:
        nonlocal duplicate_count, stale_count
        symbol_key = str(ticker or component_key or "").strip().upper()
        stable_key = "|".join(
            [
                tenant_slug,
                cycle_key,
                str(desk_key or "component").strip().lower(),
                str(event_type or "observation").strip().lower(),
                symbol_key,
                str(dimension or "").strip().lower(),
            ]
        )
        duplicate = stable_key in seen_keys
        if duplicate:
            duplicate_count += 1
        else:
            seen_keys.add(stable_key)
        stale_event = bool(stale)
        if stale_event:
            stale_count += 1
        events.append(
            {
                "stable_id": _market_ops_event_id(stable_key),
                "stable_key": stable_key,
                "tenant_slug": tenant_slug,
                "observed_at": _serialize_datetime(current),
                "source": "live_runtime_observation",
                "event_type": event_type,
                "ticker": ticker,
                "component_key": component_key,
                "desk_key": desk_key,
                "dimension": dimension,
                "metadata": serialize_value(payload or {}),
                "duplicate": duplicate,
                "stale": stale_event,
                "counts_toward_live_million": bool(enabled and not duplicate and not stale_event),
                "simulation_evidence": False,
                "paper_route_only": True,
            }
        )

    if enabled:
        for item in candidates:
            ticker = str(item.get("ticker") or item.get("symbol") or "").strip().upper()
            if not ticker:
                continue
            quote = dict(item.get("quote_freshness") or {})
            quote_status = str(quote.get("status") or "").strip().lower()
            quote_age = _diagnostic_float(item.get("quote_age_seconds") or quote.get("age_seconds"))
            stale = quote_status == "stale" or (quote_age is not None and quote_age > _TRADE_SELECTION_EDGE_MAX_QUOTE_AGE_SECONDS)
            blocker = str(item.get("blocker") or "none").strip().lower()
            ai_review = dict(item.get("ai_evidence_review") or {})
            routeability = dict(item.get("routeability") or {})
            opportunity = dict(item.get("opportunity_capture") or {})
            possibility = dict(item.get("market_possibility_engine") or {})
            execution = dict(item.get("adaptive_execution_intelligence") or {})
            edge = dict(item.get("trade_selection_edge") or {})
            against_market = dict(item.get("against_market_proxy") or {})
            spread_bps = _diagnostic_float(item.get("spread_bps") or item.get("spread_cost_bps"))
            liquidity = _diagnostic_float(item.get("average_dollar_volume") or item.get("liquidity_score"))
            ranking_score = _diagnostic_float(item.get("ranking_score") or item.get("score"))
            score_bucket = (
                "90_plus"
                if ranking_score is not None and ranking_score >= 90.0
                else "75_to_89"
                if ranking_score is not None and ranking_score >= 75.0
                else "50_to_74"
                if ranking_score is not None and ranking_score >= 50.0
                else "under_50"
                if ranking_score is not None
                else "missing"
            )
            dimensions = {
                "symbol_scan": {
                    "candidate_lifecycle_id": item.get("candidate_lifecycle_id"),
                    "status": item.get("status"),
                    "stage": item.get("stage"),
                },
                "setup_type": {
                    "opportunity_type": opportunity.get("type"),
                    "opportunity_score": opportunity.get("score"),
                },
                "blocker_state": {"blocker": blocker, "detail": item.get("detail")},
                "ai_verdict": {
                    "verdict": ai_review.get("verdict"),
                    "confidence": ai_review.get("confidence"),
                },
                "risk_gate": {
                    "risk": item.get("risk"),
                    "eligible": item.get("eligible"),
                    "routeable": routeability.get("candidate_routeable"),
                },
                "data_freshness": {"quote_status": quote_status or "unknown", "quote_age_seconds": quote_age},
                "provider_health": {
                    "provider_failure": item.get("provider_failure"),
                    "cache_state": item.get("cache_state"),
                },
                "routeability": routeability,
            }
            if capture_per_setup:
                dimensions.update(
                    {
                        "score_bucket": {
                            "ranking_score": ranking_score,
                            "score_bucket": score_bucket,
                            "stage_one_score": item.get("stage_one_score"),
                            "deep_score": item.get("deep_score"),
                        },
                        "opportunity_window": {
                            "time_window": opportunity.get("time_window"),
                            "trigger_price": opportunity.get("trigger_price"),
                            "invalid_if": opportunity.get("invalid_if"),
                            "rapid_confirmed": opportunity.get("rapid_confirmed"),
                        },
                        "regime_fit": {
                            "regime": item.get("regime") or item.get("market_regime"),
                            "regime_fit_score": item.get("regime_fit_score"),
                            "scenario_probability": possibility.get("scenario_probability"),
                        },
                        "ranking_outcome": {
                            "ranking_tier": item.get("ranking_tier"),
                            "portfolio_rank": item.get("portfolio_rank"),
                            "edge_priority_adjustment": item.get("edge_priority_adjustment"),
                            "simulation_adjustment": possibility.get("priority_adjustment"),
                        },
                    }
                )
            if capture_per_gate:
                dimensions.update(
                    {
                        "spread_quality": {
                            "spread_bps": spread_bps,
                            "spread_state": "wide" if spread_bps is not None and spread_bps > 12.5 else "acceptable",
                        },
                        "liquidity_state": {
                            "average_dollar_volume": item.get("average_dollar_volume"),
                            "liquidity_score": item.get("liquidity_score"),
                            "liquidity_state": "known" if liquidity is not None else "missing",
                        },
                        "allocator_fit": {
                            "allocator_fit_score": item.get("allocator_fit_score"),
                            "portfolio_score": item.get("portfolio_score"),
                            "bucket_exposure_after_pct": item.get("bucket_exposure_after_pct"),
                        },
                        "execution_readiness": {
                            "adaptive_execution_score": execution.get("adaptive_execution_score"),
                            "slippage_risk_score": execution.get("slippage_risk_score"),
                            "reward_risk_fit_score": execution.get("reward_risk_fit_score"),
                        },
                    }
                )
            if capture_provider_health:
                dimensions.update(
                    {
                        "against_market_state": {
                            "against_market_signal": item.get("against_market_signal") or against_market.get("signal"),
                            "proxy_symbol": item.get("proxy_symbol") or against_market.get("proxy_symbol"),
                            "bearish_confirmation_score": item.get("bearish_confirmation_score"),
                        },
                        "forecast_contract": {
                            "prediction_contract_status": item.get("prediction_contract_status"),
                            "predicted_direction": item.get("predicted_direction"),
                            "prediction_horizon_minutes": item.get("prediction_horizon_minutes"),
                        },
                        "provider_latency": {
                            "provider_latency_ms": item.get("provider_latency_ms"),
                            "cache_age_seconds": item.get("cache_age_seconds"),
                            "deep_cache_fresh": (item.get("deep_analysis") or {}).get("cache_fresh")
                            if isinstance(item.get("deep_analysis"), dict)
                            else None,
                        },
                    }
                )
            for desk_key in desk_keys:
                for dimension, payload in dimensions.items():
                    append_event(
                        event_type="candidate_observation",
                        ticker=ticker,
                        desk_key=desk_key,
                        dimension=dimension,
                        payload=payload,
                        stale=stale,
                    )
        for desk in desk_items:
            desk_key = str(desk.get("desk_key") or desk.get("key") or "").strip().lower()
            if not desk_key:
                continue
            runtime = dict(desk.get("runtime") or {})
            cadence = dict(desk.get("cadence") or {})
            allowed_tickers = [
                str(ticker or "").strip().upper()
                for ticker in list(desk.get("allowed_tickers") or [])
                if str(ticker or "").strip()
            ]
            if not allowed_tickers:
                continue
            last_scan_at = _parse_iso_datetime(runtime.get("last_scan_at"))
            next_scan_at = _parse_iso_datetime(runtime.get("next_scan_at"))
            cycle_seconds = _market_ops_safe_int(cadence.get("cycle_interval_seconds"), 60)
            scan_age_seconds = int((current - last_scan_at).total_seconds()) if last_scan_at else None
            next_scan_lag_seconds = (
                int((current - next_scan_at).total_seconds()) if next_scan_at and next_scan_at < current else 0
            )
            desk_stale = bool(
                (next_scan_lag_seconds and next_scan_lag_seconds > max(180, cycle_seconds * 4))
                or (scan_age_seconds is not None and scan_age_seconds > max(900, cycle_seconds * 8))
            )
            desk_dimensions = {
                "desk_symbol_scan_state": {
                    "desk_key": desk_key,
                    "execution_status": desk.get("execution_status"),
                    "last_scan_at": runtime.get("last_scan_at"),
                    "next_scan_at": runtime.get("next_scan_at"),
                    "scan_age_seconds": scan_age_seconds,
                    "scanned_count": runtime.get("scanned_count"),
                    "eligible_count": runtime.get("eligible_count"),
                    "top_blocker": runtime.get("top_blocker"),
                },
                "desk_symbol_schedule_state": {
                    "desk_key": desk_key,
                    "cycle_interval_seconds": cycle_seconds,
                    "next_scan_lag_seconds": next_scan_lag_seconds,
                    "worker_deferred_reason": runtime.get("worker_deferred_reason"),
                    "worker_deferred_behind": runtime.get("worker_deferred_behind"),
                },
                "desk_symbol_route_state": {
                    "desk_key": desk_key,
                    "routeable": desk.get("routeable"),
                    "can_submit_orders": desk.get("can_submit_orders"),
                    "paper_execution_route": desk.get("paper_execution_route"),
                    "provider": desk.get("provider"),
                },
                "desk_symbol_risk_budget": {
                    "desk_key": desk_key,
                    "risk_budget": desk.get("risk_budget"),
                    "objective_role": desk.get("objective_role"),
                    "target_pressure": desk.get("target_pressure"),
                },
            }
            for ticker in allowed_tickers:
                for dimension, payload in desk_dimensions.items():
                    append_event(
                        event_type="desk_symbol_observation",
                        ticker=ticker,
                        desk_key=desk_key,
                        dimension=dimension,
                        payload=payload,
                        stale=desk_stale,
                    )
    for component in list(components or []):
        if not isinstance(component, dict):
            continue
        append_event(
            event_type="session_component_observation",
            component_key=str(component.get("key") or component.get("label") or "component"),
            dimension=str(component.get("status") or "status"),
            payload={
                "status": component.get("status"),
                "detail": component.get("detail"),
                "next_action": component.get("next_action"),
            },
            stale=False,
        )
    generated_count = len(events)
    duplicate_ratio_all = duplicate_count / generated_count if generated_count else 0.0
    stale_ratio_all = min(stale_count, generated_count) / generated_count if generated_count else 0.0
    backoff_reasons: list[str] = []
    if aggressive_mode and duplicate_ratio_all > backoff_duplicate_ratio:
        backoff_reasons.append("duplicate_ratio_guard")
    if aggressive_mode and stale_ratio_all > backoff_stale_ratio:
        backoff_reasons.append("stale_ratio_guard")
    effective_max_events = min(max_events, backoff_min_events) if backoff_reasons else max_events
    rate_limited_count = max(generated_count - effective_max_events, 0)
    rows_to_write = events[:effective_max_events]
    useful_count = sum(1 for event in rows_to_write if event.get("counts_toward_live_million"))
    trade_supporting_count = sum(
        1
        for event in rows_to_write
        if str((event.get("metadata") or {}).get("status") or "").lower() == "eligible"
        or bool((event.get("metadata") or {}).get("routeable"))
    )
    blocker_count = sum(1 for event in rows_to_write if str((event.get("metadata") or {}).get("blocker") or "none") != "none")
    ai_count = sum(1 for event in rows_to_write if event.get("dimension") == "ai_verdict")
    written_count = 0
    write_error = None
    write_duration_ms = 0.0
    if persist and rows_to_write:
        try:
            target.parent.mkdir(parents=True, exist_ok=True)
            write_started = perf_counter()
            with target.open("a", encoding="utf-8") as handle:
                for row in rows_to_write:
                    handle.write(json.dumps(serialize_value(row), sort_keys=True) + "\n")
                    written_count += 1
            write_duration_ms = round((perf_counter() - write_started) * 1000.0, 3)
        except OSError as exc:
            write_error = str(exc)
    if write_duration_ms > float(write_lag_warning_ms):
        backoff_reasons.append("write_lag_guard")
    total_observations = len(rows_to_write)
    useful_ratio = useful_count / total_observations if total_observations else 0.0
    duplicate_ratio = duplicate_count / len(events) if events else 0.0
    stale_ratio = min(stale_count, len(events)) / len(events) if events else 0.0
    return serialize_value(
        {
            "status": SAFETY_STATE_READY if enabled and write_error is None and not backoff_reasons else SAFETY_STATE_DEGRADED,
            "enabled": enabled,
            "mode": "aggressive_guarded" if aggressive_mode else "maximum_guarded",
            "source": "live_runtime_observation",
            "include_all_desks": include_all_desks,
            "capture_per_gate": capture_per_gate,
            "capture_per_setup": capture_per_setup,
            "capture_provider_health": capture_provider_health,
            "configured_max_events_per_minute": max_events,
            "effective_max_events_per_minute": effective_max_events,
            "backoff_active": bool(backoff_reasons),
            "backoff_reasons": backoff_reasons,
            "backoff_thresholds": {
                "duplicate_ratio": backoff_duplicate_ratio,
                "stale_ratio": backoff_stale_ratio,
                "write_lag_warning_ms": write_lag_warning_ms,
                "backoff_min_events_per_minute": backoff_min_events,
            },
            "candidate_count": len(candidates),
            "desk_count": len(desk_keys),
            "attempted_event_count": generated_count,
            "rate_limited_count": rate_limited_count,
            "live_observed_increment": useful_count if persist else 0,
            "current_useful_event_count": useful_count,
            "duplicate_count": duplicate_count,
            "stale_count": min(stale_count, len(events)),
            "trade_supporting_count": trade_supporting_count,
            "blocker_count": blocker_count,
            "ai_review_count": ai_count,
            "useful_event_ratio": round(useful_ratio, 6),
            "duplicate_ratio": round(duplicate_ratio, 6),
            "stale_ratio": round(stale_ratio, 6),
            "trade_supporting_ratio": round(trade_supporting_count / total_observations, 6) if total_observations else 0.0,
            "written_count": written_count,
            "write_duration_ms": write_duration_ms,
            "path": str(target),
            "write_error": write_error,
            "counts_toward_live_million": True,
            "simulation_counts_toward_live_million": False,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "latest_rows": rows_to_write[:20],
            "next_action": (
                "Evidence Accelerator backed down this heartbeat because quality or write-lag guardrails tripped; keep collecting without inflating stale or duplicate evidence."
                if backoff_reasons
                else
                "Accelerator is collecting richer live observations from every candidate, desk, blocker, AI verdict, risk gate, and provider state."
                if enabled
                else "Enable EVIDENCE_ACCELERATOR_ENABLED to collect accelerated live observations."
            ),
            "summary": {
                "scanned_count": summary.get("scanned_count"),
                "eligible_count": summary.get("eligible_count"),
                "top_blocker": summary.get("top_blocker"),
            },
        }
    )


def _market_ops_simulation_evidence_snapshot(
    *,
    tenant_slug: str,
    candidate_diagnostics: dict[str, Any] | None = None,
    now: datetime | None = None,
    persist: bool = False,
) -> dict[str, Any]:
    current = now or _utc_now()
    diagnostics = dict(candidate_diagnostics or {})
    candidates = [dict(item) for item in list(diagnostics.get("candidates") or []) if isinstance(item, dict)]
    day = current.astimezone(_TRADE_AUTOMATION_MARKET_TZ).date().isoformat()
    target = _SIMULATION_EVIDENCE_ROOT / day / f"{tenant_slug}.jsonl"
    rows: list[dict[str, Any]] = []
    for item in candidates:
        possibility = dict(item.get("market_possibility_engine") or {})
        if not possibility:
            continue
        rows.append(
            {
                "stable_id": _market_ops_event_id(
                    tenant_slug,
                    item.get("candidate_lifecycle_id"),
                    possibility.get("model_version"),
                    diagnostics.get("evaluated_at") or _serialize_datetime(current),
                ),
                "tenant_slug": tenant_slug,
                "created_at": _serialize_datetime(current),
                "source": "simulation_evidence",
                "candidate_lifecycle_id": item.get("candidate_lifecycle_id"),
                "ticker": item.get("ticker"),
                "model_version": possibility.get("model_version") or _MARKET_POSSIBILITY_MODEL_VERSION,
                "scenario_count": possibility.get("scenario_count"),
                "scenario_probability": possibility.get("scenario_probability"),
                "expected_move_pct": possibility.get("expected_move_pct"),
                "expected_value_score": possibility.get("expected_value_score"),
                "downside_probability": possibility.get("downside_probability"),
                "scenario_rank": possibility.get("scenario_rank"),
                "best_case": possibility.get("best_case"),
                "base_case": possibility.get("base_case"),
                "worst_case": possibility.get("worst_case"),
                "invalid_if": possibility.get("invalid_if"),
                "simulation_reason_codes": possibility.get("simulation_reason_codes") or [],
                "counts_toward_live_million": False,
                "can_submit_orders": False,
                "can_submit_live_orders": False,
            }
        )
    written_count = 0
    write_error = None
    if persist and rows:
        try:
            target.parent.mkdir(parents=True, exist_ok=True)
            with target.open("a", encoding="utf-8") as handle:
                for row in rows:
                    handle.write(json.dumps(serialize_value(row), sort_keys=True) + "\n")
                    written_count += 1
        except OSError as exc:
            write_error = str(exc)
    probabilities = [
        float(row.get("scenario_probability") or 0.0)
        for row in rows
        if row.get("scenario_probability") is not None
    ]
    expected_values = [
        float(row.get("expected_value_score") or 0.0)
        for row in rows
        if row.get("expected_value_score") is not None
    ]
    return serialize_value(
        {
            "status": SAFETY_STATE_READY if write_error is None else SAFETY_STATE_DEGRADED,
            "enabled": bool(getattr(settings, "market_possibility_engine_enabled", True)),
            "source": "simulation_evidence",
            "simulation_evidence_increment": written_count if persist else 0,
            "current_simulation_event_count": len(rows),
            "average_scenario_probability": round(sum(probabilities) / len(probabilities), 4) if probabilities else None,
            "average_expected_value_score": round(sum(expected_values) / len(expected_values), 4) if expected_values else None,
            "model_version": _MARKET_POSSIBILITY_MODEL_VERSION,
            "counts_toward_live_million": False,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "written_count": written_count,
            "path": str(target),
            "write_error": write_error,
            "latest_rows": rows[:10],
            "next_action": "Simulation evidence is stored separately and can improve ranking/reports without inflating the live 100M target.",
        }
    )


def _market_ops_evidence_million_target(
    *,
    tenant_slug: str,
    candidate_diagnostics: dict[str, Any] | None = None,
    desks_payload: dict[str, Any] | None = None,
    no_trade_report: dict[str, Any] | None = None,
    lifecycle_artifact: dict[str, Any] | None = None,
    components: list[dict[str, Any]] | None = None,
    roadmap_activation: dict[str, Any] | None = None,
    read_only_activation_audit: dict[str, Any] | None = None,
    now: datetime | None = None,
    persist: bool = False,
) -> dict[str, Any]:
    current = now or _utc_now()
    diagnostics = dict(candidate_diagnostics or {})
    summary = dict(diagnostics.get("summary") or {})
    lifecycle = dict(lifecycle_artifact or summary.get("candidate_lifecycle_artifact") or {})
    no_trade = dict(no_trade_report or {})
    previous = _market_ops_read_json_file(_EVIDENCE_MILLION_PROGRESS_PATH)
    previous_sources = dict(previous.get("event_sources") or {})
    previous_simulation_sources = dict(previous.get("simulation_sources") or {})

    lifecycle_written = _market_ops_safe_int(lifecycle.get("written_count"))
    if previous:
        lifecycle_total = _market_ops_safe_int(previous_sources.get("candidate_lifecycle_rows")) + (
            lifecycle_written if persist else 0
        )
    else:
        lifecycle_total = max(
            _market_ops_count_candidate_lifecycle_rows(tenant_slug),
            lifecycle_written,
            _market_ops_safe_int(lifecycle.get("tracked_count")),
        )

    candidates = [item for item in list(diagnostics.get("candidates") or []) if isinstance(item, dict)]
    blockers = dict(summary.get("blockers_by_reason") or {})
    ai_review = dict(summary.get("ai_evidence_review") or {})
    missed = list(no_trade.get("missed_opportunities") or summary.get("missed_opportunities") or [])
    strong_missed_count = _market_ops_safe_int(no_trade.get("strong_missed_opportunity_count"))
    components_count = len(components or [])
    accelerator_snapshot = _market_ops_evidence_accelerator_snapshot(
        tenant_slug=tenant_slug,
        candidate_diagnostics=diagnostics,
        desks_payload=desks_payload,
        components=components,
        now=current,
        persist=persist,
    )
    simulation_snapshot = _market_ops_simulation_evidence_snapshot(
        tenant_slug=tenant_slug,
        candidate_diagnostics=diagnostics,
        now=current,
        persist=persist,
    )
    increment = {
        "diagnostic_summaries": 1 if persist and diagnostics else 0,
        "market_session_snapshots": 1 if persist and components is not None else 0,
        "no_trade_reports": 1 if persist and no_trade else 0,
        "ai_review_observations": _market_ops_safe_int(ai_review.get("reviewed_count")) if persist else 0,
        "blocker_observations": sum(_market_ops_safe_int(value) for value in blockers.values()) if persist else 0,
        "missed_move_observations": (len(missed) + strong_missed_count) if persist else 0,
        "market_ops_component_observations": components_count if persist else 0,
        "roadmap_activation_snapshots": 1 if persist and roadmap_activation else 0,
        "read_only_audit_snapshots": 1 if persist and read_only_activation_audit else 0,
        "evidence_accelerator_live_observations": _market_ops_safe_int(
            accelerator_snapshot.get("live_observed_increment")
        )
        if persist
        else 0,
    }
    event_sources = {
        "candidate_lifecycle_rows": lifecycle_total,
        "diagnostic_summaries": _market_ops_safe_int(previous_sources.get("diagnostic_summaries"))
        + increment["diagnostic_summaries"],
        "market_session_snapshots": _market_ops_safe_int(previous_sources.get("market_session_snapshots"))
        + increment["market_session_snapshots"],
        "no_trade_reports": _market_ops_safe_int(previous_sources.get("no_trade_reports")) + increment["no_trade_reports"],
        "ai_review_observations": _market_ops_safe_int(previous_sources.get("ai_review_observations"))
        + increment["ai_review_observations"],
        "blocker_observations": _market_ops_safe_int(previous_sources.get("blocker_observations"))
        + increment["blocker_observations"],
        "missed_move_observations": _market_ops_safe_int(previous_sources.get("missed_move_observations"))
        + increment["missed_move_observations"],
        "market_ops_component_observations": _market_ops_safe_int(
            previous_sources.get("market_ops_component_observations")
        )
        + increment["market_ops_component_observations"],
        "roadmap_activation_snapshots": _market_ops_safe_int(previous_sources.get("roadmap_activation_snapshots"))
        + increment["roadmap_activation_snapshots"],
        "read_only_audit_snapshots": _market_ops_safe_int(previous_sources.get("read_only_audit_snapshots"))
        + increment["read_only_audit_snapshots"],
        "evidence_accelerator_live_observations": _market_ops_safe_int(
            previous_sources.get("evidence_accelerator_live_observations")
        )
        + increment["evidence_accelerator_live_observations"],
    }
    previous_sources_total = sum(_market_ops_safe_int(value) for value in previous_sources.values())
    previous_observed_count = _market_ops_safe_int(previous.get("observed_event_count"))
    for source_name, source_value in previous_sources.items():
        if source_name not in event_sources:
            event_sources[source_name] = _market_ops_safe_int(source_value)
    prior_progress_gap = max(previous_observed_count - previous_sources_total, 0)
    if prior_progress_gap:
        event_sources["prior_progress_observations"] = (
            _market_ops_safe_int(event_sources.get("prior_progress_observations")) + prior_progress_gap
        )
    observed_count = sum(event_sources.values())
    simulation_sources = {
        "market_possibility_scenario_batches": _market_ops_safe_int(
            previous_simulation_sources.get("market_possibility_scenario_batches")
        )
        + (_market_ops_safe_int(simulation_snapshot.get("simulation_evidence_increment")) if persist else 0),
    }
    simulation_count = sum(simulation_sources.values())
    progress_pct = min(100.0, (observed_count / _EVIDENCE_MILLION_TARGET_COUNT) * 100.0)
    active_item_count = _market_ops_safe_int((roadmap_activation or {}).get("active_item_count"))
    current_useful = _market_ops_safe_int(accelerator_snapshot.get("current_useful_event_count"))
    current_duplicates = _market_ops_safe_int(accelerator_snapshot.get("duplicate_count"))
    current_stale = _market_ops_safe_int(accelerator_snapshot.get("stale_count"))
    current_total = max(
        _market_ops_safe_int(accelerator_snapshot.get("attempted_event_count")),
        current_useful + current_duplicates + current_stale,
    )
    evidence_quality = {
        "status": accelerator_snapshot.get("status") or SAFETY_STATE_READY,
        "live_observed_evidence": observed_count,
        "simulation_evidence": simulation_count,
        "useful_event_count": current_useful,
        "duplicate_count": current_duplicates,
        "stale_count": current_stale,
        "trade_supporting_count": _market_ops_safe_int(accelerator_snapshot.get("trade_supporting_count")),
        "blocker_count": _market_ops_safe_int(accelerator_snapshot.get("blocker_count")),
        "ai_review_count": _market_ops_safe_int(accelerator_snapshot.get("ai_review_count")),
        "useful_event_ratio": float(accelerator_snapshot.get("useful_event_ratio") or 0.0),
        "duplicate_ratio": float(accelerator_snapshot.get("duplicate_ratio") or 0.0),
        "stale_ratio": float(accelerator_snapshot.get("stale_ratio") or 0.0),
        "trade_supporting_ratio": float(accelerator_snapshot.get("trade_supporting_ratio") or 0.0),
        "quality_score": round(
            max(
                0.0,
                min(
                    100.0,
                    (float(accelerator_snapshot.get("useful_event_ratio") or 0.0) * 100.0)
                    - (float(accelerator_snapshot.get("duplicate_ratio") or 0.0) * 20.0)
                    - (float(accelerator_snapshot.get("stale_ratio") or 0.0) * 35.0),
                ),
            ),
            4,
        )
        if current_total
        else 0.0,
        "simulation_counts_toward_live_million": False,
    }
    payload = {
        "status": SAFETY_STATE_READY,
        "label": "Evidence 100M",
        "target_event_count": _EVIDENCE_MILLION_TARGET_COUNT,
        "observed_event_count": observed_count,
        "live_observed_evidence": observed_count,
        "simulation_evidence": simulation_count,
        "remaining_event_count": max(_EVIDENCE_MILLION_TARGET_COUNT - observed_count, 0),
        "progress_pct": round(progress_pct, 4),
        "event_sources": event_sources,
        "simulation_sources": simulation_sources,
        "last_increment": increment,
        "evidence_quality": evidence_quality,
        "evidence_accelerator": accelerator_snapshot,
        "market_possibility_engine": simulation_snapshot,
        "active_paper_evidence_item_count": active_item_count,
        "active_bundle_count": _market_ops_safe_int((roadmap_activation or {}).get("active_bundle_count")),
        "read_only_bundle_count": _market_ops_safe_int((read_only_activation_audit or {}).get("read_only_count")),
        "usage_mode": "evidence_memory_target",
        "mutation": "paper_evidence_state",
        "can_write_artifacts": True,
        "writes_trade_state": False,
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "paper_route_only": True,
        "live_mirror": {
            "available": True,
            "enabled": False,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "status": "available_disabled",
        },
        "evidence_event_types": [
            "candidate_lifecycle",
            "rejected_candidate",
            "blocker_snapshot",
            "ai_evidence_review",
            "missed_move_review",
            "market_session_snapshot",
            "roadmap_activation_snapshot",
            "read_only_activation_audit",
            "accelerated_symbol_observation",
            "accelerated_desk_symbol_observation",
            "accelerated_setup_type",
            "accelerated_blocker_state",
            "accelerated_ai_verdict",
            "accelerated_risk_gate",
            "accelerated_data_freshness",
            "accelerated_provider_health",
        ],
        "simulation_event_types": [
            "market_possibility_scenario_batch",
            "trend_continuation_path",
            "failed_breakout_path",
            "vwap_reclaim_path",
            "vwap_rejection_path",
            "range_chop_path",
            "risk_off_acceleration_path",
            "reversal_path",
            "volatility_expansion_path",
            "liquidity_deterioration_path",
        ],
        "simulation_counts_toward_live_million": False,
        "progress_path": str(_EVIDENCE_MILLION_PROGRESS_PATH),
        "updated_at": _serialize_datetime(current),
        "next_action": (
            "Keep collecting accelerated live observations; simulation evidence can improve ranking but never inflates the live 100M target."
        ),
    }
    if persist:
        try:
            _EVIDENCE_MILLION_STATE_ROOT.mkdir(parents=True, exist_ok=True)
            _EVIDENCE_MILLION_PROGRESS_PATH.write_text(
                json.dumps(serialize_value(payload), indent=2, sort_keys=True),
                encoding="utf-8",
            )
            payload["artifact_written"] = True
        except OSError as exc:
            payload["status"] = SAFETY_STATE_DEGRADED
            payload["artifact_written"] = False
            payload["write_error"] = str(exc)
            payload["next_action"] = "Evidence 100M progress could not be written; repair artifact storage before relying on the progress target."
    return serialize_value(payload)
_MARKET_OPS_ROUTE_ENDPOINTS = {
    "watchdog": "/api/orgs/trade-automation/watchdog",
    "market_session": "/api/orgs/trade-automation/market-session",
    "no_trade_report": "/api/orgs/trade-automation/no-trade-report",
    "market_day_report": "/api/orgs/trade-automation/market-day-report",
    "position_promotion": "/api/orgs/trade-automation/position-promotion",
    "candidate_diagnostics": "/api/orgs/trade-automation/candidate-diagnostics",
    "desks": "/api/orgs/trade-automation/desks",
    "safety_ledger": "/api/orgs/trade-automation/daily-ledger",
    "market_ready_report": "python scripts/trading_safety_tools.py market-ready --env-file .env --tenant-slug systematic-equities",
}
_PRODUCTION_TRUST_ROOT = _EVIDENCE_RUNTIME_EXPORT_ROOT / "production-trust"
_SUPPORT_BUNDLE_ROOT = Path("runtime-exports") / "support-bundles"
_REPLAY_REPORT_ROOT = Path("runtime-exports") / "replay-reports"
_PRODUCTION_TRUST_SECRET_MARKERS = (
    "secret",
    "token",
    "password",
    "api_key",
    "apikey",
    "authorization",
    "credential",
    "private_key",
    "key_id",
)


def _production_trust_day_key(day: date | str | None = None) -> str:
    if isinstance(day, date):
        return day.isoformat()
    return str(day or datetime.now(_TRADE_AUTOMATION_MARKET_TZ).date().isoformat())


def _production_trust_env_value(*keys: str) -> str:
    for key in keys:
        value = str(os.getenv(key) or "").strip()
        if value:
            return value
    return ""


def _production_trust_sanitize(value: Any, *, key_hint: str = "") -> Any:
    key_normalized = key_hint.lower()
    if any(marker in key_normalized for marker in _PRODUCTION_TRUST_SECRET_MARKERS):
        return "***redacted***" if value not in {None, "", False} else value
    if isinstance(value, dict):
        return {str(key): _production_trust_sanitize(item, key_hint=str(key)) for key, item in value.items()}
    if isinstance(value, list):
        return [_production_trust_sanitize(item, key_hint=key_hint) for item in value]
    if isinstance(value, tuple):
        return tuple(_production_trust_sanitize(item, key_hint=key_hint) for item in value)
    return value


def _production_trust_write_json(path: Path, payload: dict[str, Any]) -> dict[str, Any]:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(serialize_value(payload), indent=2, sort_keys=True), encoding="utf-8")
        return {"written": True, "path": str(path)}
    except OSError as exc:
        return {"written": False, "path": str(path), "error": str(exc)}


def _production_trust_alert_delivery_status(now: datetime | None = None) -> dict[str, Any]:
    current = now or _utc_now()
    smtp_host = _production_trust_env_value("PRODUCTION_TRUST_SMTP_HOST", "TRUST_ALERT_SMTP_HOST", "SMTP_HOST")
    smtp_from = _production_trust_env_value("PRODUCTION_TRUST_SMTP_FROM", "TRUST_ALERT_SMTP_FROM", "SMTP_FROM")
    smtp_to = _production_trust_env_value("PRODUCTION_TRUST_SMTP_TO", "TRUST_ALERT_SMTP_TO", "SMTP_TO")
    smtp_port = _production_trust_env_value("PRODUCTION_TRUST_SMTP_PORT", "TRUST_ALERT_SMTP_PORT", "SMTP_PORT") or "587"
    webhook_url = _production_trust_env_value("PRODUCTION_TRUST_WEBHOOK_URL", "TRUST_ALERT_WEBHOOK_URL", "WEBHOOK_URL")
    cooldown_seconds = _market_ops_safe_int(
        _production_trust_env_value("PRODUCTION_TRUST_ALERT_COOLDOWN_SECONDS", "TRUST_ALERT_COOLDOWN_SECONDS"),
        900,
    )
    smtp_missing = [
        label
        for label, configured in {
            "smtp_host": bool(smtp_host),
            "smtp_from": bool(smtp_from),
            "smtp_to": bool(smtp_to),
        }.items()
        if not configured
    ]
    email_configured = not smtp_missing
    webhook_configured = bool(webhook_url)
    enabled = email_configured or webhook_configured
    channels = [
        {
            "key": "email",
            "label": "SMTP email",
            "configured": email_configured,
            "status": "ready" if email_configured else "not_configured",
            "missing": smtp_missing,
            "host_present": bool(smtp_host),
            "port": smtp_port,
            "from_present": bool(smtp_from),
            "to_present": bool(smtp_to),
            "secrets_exposed": False,
        },
        {
            "key": "webhook",
            "label": "Generic webhook",
            "configured": webhook_configured,
            "status": "ready" if webhook_configured else "not_configured",
            "missing": [] if webhook_configured else ["webhook_url"],
            "url_present": bool(webhook_url),
            "secrets_exposed": False,
        },
    ]
    triggers = [
        "watchdog_degraded",
        "watchdog_blocked",
        "watchdog_killed",
        "kill_switch",
        "stale_worker",
        "stale_deep_queue",
        "alpaca_route_failure",
        "reconciliation_blocker",
        "no_trade_checkpoint",
        "provider_data_failure",
    ]
    return serialize_value(
        {
            "status": "ready" if enabled else "not_configured",
            "enabled": enabled,
            "mode": "email_webhook_first",
            "generated_at": _serialize_datetime(current),
            "channels": channels,
            "configured_channel_count": sum(1 for item in channels if item["configured"]),
            "cooldown_seconds": cooldown_seconds,
            "dedupe_key_fields": ["event_type", "blocker", "market_day"],
            "triggers": triggers,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "next_action": (
                "Alert delivery is configured; use the test endpoint to write a safe delivery proof."
                if enabled
                else "Configure SMTP or webhook environment variables to enable out-of-app Watchdog alerts."
            ),
        }
    )


def _production_trust_evidence_quality(
    evidence_million: dict[str, Any] | None = None,
    *,
    candidate_diagnostics: dict[str, Any] | None = None,
    no_trade_report: dict[str, Any] | None = None,
    components: list[dict[str, Any]] | None = None,
    now: datetime | None = None,
) -> dict[str, Any]:
    current = now or _utc_now()
    evidence = dict(evidence_million or _market_ops_read_json_file(_EVIDENCE_MILLION_PROGRESS_PATH))
    sources = dict(evidence.get("event_sources") or {})
    summary = dict((candidate_diagnostics or {}).get("summary") or {})
    blockers_by_reason = dict(summary.get("blockers_by_reason") or {})
    no_trade = dict(no_trade_report or {})
    observed = _market_ops_safe_int(evidence.get("observed_event_count") or sum(_market_ops_safe_int(v) for v in sources.values()))
    ai_review = _market_ops_safe_int(sources.get("ai_review_observations"))
    blocker = _market_ops_safe_int(sources.get("blocker_observations")) + sum(
        _market_ops_safe_int(value) for value in blockers_by_reason.values()
    )
    missed_move = _market_ops_safe_int(sources.get("missed_move_observations")) + _market_ops_safe_int(
        no_trade.get("strong_missed_opportunity_count")
    )
    session_proof = _market_ops_safe_int(sources.get("market_session_snapshots")) + len(components or [])
    trade_supporting = _market_ops_safe_int(sources.get("candidate_lifecycle_rows")) + _market_ops_safe_int(
        sources.get("diagnostic_summaries")
    )
    duplicate = min(
        observed,
        _market_ops_safe_int(sources.get("read_only_audit_snapshots")) // 4
        + _market_ops_safe_int(sources.get("roadmap_activation_snapshots")) // 4,
    )
    stale = 0
    if str(summary.get("top_blocker") or "").lower().find("stale") >= 0:
        stale += 1
    stale += sum(1 for item in components or [] if str(item.get("status") or "").lower() == SAFETY_STATE_DEGRADED and "stale" in str(item).lower())
    useful = max(observed - duplicate - stale, 0)
    useful_rate = (useful / observed) if observed else 0.0
    duplicate_ratio = (duplicate / observed) if observed else 0.0
    stale_ratio = (stale / observed) if observed else 0.0
    quality_score = max(0.0, min(100.0, (useful_rate * 100.0) - (duplicate_ratio * 20.0) - (stale_ratio * 35.0)))
    status = SAFETY_STATE_READY if observed and quality_score >= 80 else SAFETY_STATE_DEGRADED if observed else "not_configured"
    return serialize_value(
        {
            "status": status,
            "generated_at": _serialize_datetime(current),
            "target_event_count": _market_ops_safe_int(evidence.get("target_event_count"), _EVIDENCE_MILLION_TARGET_COUNT),
            "observed_event_count": observed,
            "quality_score": round(quality_score, 2),
            "duplicate_ratio": round(duplicate_ratio, 4),
            "stale_ratio": round(stale_ratio, 4),
            "useful_event_rate": round(useful_rate, 4),
            "categories": {
                "useful": useful,
                "duplicate": duplicate,
                "stale": stale,
                "trade_supporting": trade_supporting,
                "blocker": blocker,
                "missed_move": missed_move,
                "ai_review": ai_review,
                "session_proof": session_proof,
            },
            "raw_volume_is_not_enough": True,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "next_action": (
                "Evidence quality is healthy; keep collecting real candidate, blocker, AI, missed-move, and session proof."
                if status == SAFETY_STATE_READY
                else "Increase useful real observations and reduce stale or duplicate evidence before treating 1M as production proof."
            ),
        }
    )


def _production_trust_provider_reliability(
    candidate_diagnostics: dict[str, Any] | None = None,
    *,
    now: datetime | None = None,
) -> dict[str, Any]:
    current = now or _utc_now()
    diagnostics = dict(candidate_diagnostics or {})
    summary = dict(diagnostics.get("summary") or {})
    candidates = [item for item in list(diagnostics.get("candidates") or []) if isinstance(item, dict)]
    stale_quote_count = 0
    stale_ohlcv_count = 0
    provider_failures: set[str] = set()
    max_quote_age: float | None = None
    for item in candidates:
        quote_age = item.get("quote_age_seconds") or item.get("quote_freshness_seconds") or item.get("data_age_seconds")
        try:
            quote_age_num = float(quote_age)
            max_quote_age = quote_age_num if max_quote_age is None else max(max_quote_age, quote_age_num)
            if quote_age_num > 120:
                stale_quote_count += 1
        except (TypeError, ValueError):
            pass
        ohlcv_age = item.get("ohlcv_age_seconds") or item.get("volume_age_seconds")
        try:
            if float(ohlcv_age) > 300:
                stale_ohlcv_count += 1
        except (TypeError, ValueError):
            pass
        failure = item.get("provider_failure") or item.get("data_provider_error")
        if failure:
            provider_failures.add(str(failure))
    timeout_count = _market_ops_safe_int(summary.get("provider_timeout_count") or summary.get("timeout_count"))
    failure_count = len(provider_failures) + _market_ops_safe_int(summary.get("failed_provider_symbol_count"))
    status = SAFETY_STATE_BLOCKED if failure_count and stale_quote_count >= max(1, len(candidates) // 2) else SAFETY_STATE_DEGRADED if failure_count or stale_quote_count or stale_ohlcv_count or timeout_count else SAFETY_STATE_READY
    return serialize_value(
        {
            "status": status,
            "generated_at": _serialize_datetime(current),
            "scanned_count": _market_ops_safe_int(summary.get("scanned_count") or len(candidates)),
            "quote_freshness": {
                "stale_count": stale_quote_count,
                "max_age_seconds": max_quote_age,
                "status": SAFETY_STATE_DEGRADED if stale_quote_count else SAFETY_STATE_READY,
            },
            "ohlcv_freshness": {
                "stale_count": stale_ohlcv_count,
                "status": SAFETY_STATE_DEGRADED if stale_ohlcv_count else SAFETY_STATE_READY,
            },
            "provider_errors": {
                "timeout_count": timeout_count,
                "failure_count": failure_count,
                "failure_types": sorted(provider_failures)[:10],
            },
            "stale_cache_use": {
                "detected": bool(summary.get("stale_cache_warning") or stale_quote_count),
                "source": "candidate_diagnostics",
            },
            "corporate_action_awareness": {"status": "modeled", "enabled": False, "next_action": "Add a provider-backed corporate-action feed before live enablement."},
            "market_halt_warning": {"status": "modeled", "enabled": False, "next_action": "Wire halt feed before relying on live-disabled enterprise mirrors."},
            "earnings_event_proximity": {"status": "modeled", "enabled": False, "next_action": "Wire event calendar before promoting event-sensitive desks."},
            "fallback_availability": {"status": "paper_primary", "configured": True, "fallback_route_can_submit_orders": False},
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "next_action": (
                "Provider data is clean enough for paper evidence monitoring."
                if status == SAFETY_STATE_READY
                else "Resolve stale quotes, OHLCV freshness, or provider errors before expecting reliable entries."
            ),
        }
    )


def _production_trust_auth_provider_status() -> dict[str, Any]:
    provider = _production_trust_env_value("AUTH_PROVIDER", "VITE_AUTH_PROVIDER").lower()
    local_mode = _production_trust_env_value("LOCAL_AUTH_ENABLED", "DEMO_AUTH_ENABLED")
    if provider in {"auth0", "okta", "cognito", "azure_ad", "entra"}:
        status = "configured"
        label = provider
    elif provider:
        status = "not_implemented"
        label = provider
    elif str(local_mode).lower() in {"1", "true", "yes", "on"}:
        status = "local_demo"
        label = "local/demo"
    else:
        status = "local_demo"
        label = "local/demo"
    return {
        "status": status,
        "label": label,
        "customer_copy": "Authentication status is surfaced for support and compliance proof.",
        "can_enable_live_trading": False,
    }


def _production_trust_onboarding_checklist(
    *,
    market_session: dict[str, Any],
    alert_delivery: dict[str, Any],
    evidence_quality: dict[str, Any],
    provider_reliability: dict[str, Any],
) -> dict[str, Any]:
    safety = dict(market_session.get("safety_state") or {})
    alpaca = dict(market_session.get("alpaca_reconciliation_console") or {})
    phase = dict(market_session.get("phase") or {})
    desks = dict(market_session.get("desks") or {})
    settings_proof = dict(market_session.get("expected_settings_proof") or {})
    continuous = _market_ops_read_json_file(_CONTINUOUS_OPS_LATEST_PATH)
    evidence = dict(market_session.get("evidence_million_target") or {})
    weekly_objective_ready = True
    daily_objective = dict(market_session.get("entry_window_explainer", {}).get("daily_objective") or {})
    if daily_objective:
        weekly_objective_ready = bool(
            daily_objective.get("weekly_profit_target_min_pct")
            or daily_objective.get("weekly_profit_target_max_pct")
            or daily_objective.get("enabled")
        )
    items = [
        ("alpaca_paper_keys", "Alpaca paper keys present", True, "Presence is checked without exposing secrets."),
        ("paper_route_selected", "Alpaca paper route selected", bool(market_session.get("paper_route_only", True)), "Route must remain broker_paper for unattended entries."),
        ("market_watchdog_reachable", "Market Watchdog reachable", True, "Watchdog is built from the current backend request."),
        ("continuous_ops_running", "Continuous Ops running", bool(continuous), "Start Continuous Ops for 24/7 app and evidence monitoring."),
        ("kill_switch_off", "Kill switch off", str(safety.get("status") or "").lower() != SAFETY_STATE_KILLED, "Clear manually only after reconciliation proof is clean."),
        ("reconciliation_clean", "Reconciliation clean", str(alpaca.get("status") or "").lower() in {"ready", "watching", ""}, "Paper order state must match broker evidence."),
        ("risk_caps_present", "Risk caps present", str(settings_proof.get("status") or "").lower() == SAFETY_STATE_READY, "Route, account floor, symbols, risk caps, kill switch, and desks are checked."),
        ("weekly_objective_set", "Weekly objective set", weekly_objective_ready, "Objective is a target, not a guarantee or risk override."),
        ("desks_armed", "Active desks armed", _market_ops_safe_int(desks.get("active_armed_count")) >= len(_TRADE_AUTOMATION_DESK_DEFAULTS), "All five active engines should be enabled and armed."),
        ("evidence_million_collecting", "Evidence 100M collecting", _market_ops_safe_int(evidence.get("observed_event_count")) > 0, "Evidence count and quality are tracked together."),
        ("alerts_configured", "Out-of-app alerts configured", bool(alert_delivery.get("enabled")), "SMTP/webhook alerts are optional until configured."),
        ("provider_reliability_visible", "Provider reliability visible", bool(provider_reliability), "Quote, OHLCV, timeout, and fallback states are surfaced."),
        ("evidence_quality_visible", "Evidence quality visible", bool(evidence_quality), "Useful/stale/duplicate evidence mix is scored."),
    ]
    rows = [
        {
            "key": key,
            "label": label,
            "status": SAFETY_STATE_READY if ok else "not_configured",
            "complete": bool(ok),
            "detail": detail,
        }
        for key, label, ok, detail in items
    ]
    completed = sum(1 for item in rows if item["complete"])
    return serialize_value(
        {
            "status": SAFETY_STATE_READY if completed == len(rows) else "needs_attention",
            "completed_count": completed,
            "total_count": len(rows),
            "progress_pct": round((completed / len(rows)) * 100.0, 2) if rows else 0.0,
            "items": rows,
            "phase": phase.get("phase"),
            "can_enable_live_trading": False,
            "next_action": (
                "Onboarding is complete for Alpaca paper operation."
                if completed == len(rows)
                else "Finish incomplete checklist items before treating the customer environment as launch-ready."
            ),
        }
    )


def _production_trust_replay_report(
    *,
    tenant_slug: str,
    day: date | str | None = None,
    candidate_diagnostics: dict[str, Any] | None = None,
    no_trade_report: dict[str, Any] | None = None,
    market_day_report: dict[str, Any] | None = None,
    persist: bool = False,
) -> dict[str, Any]:
    day_key = _production_trust_day_key(day)
    diagnostics = dict(candidate_diagnostics or {})
    summary = dict(diagnostics.get("summary") or {})
    no_trade = dict(no_trade_report or {})
    market_day = dict(market_day_report or {})
    missed = list(no_trade.get("missed_opportunities") or summary.get("missed_opportunities") or [])
    strong_missed = _market_ops_safe_int(no_trade.get("strong_missed_opportunity_count"))
    blockers = dict(summary.get("blockers_by_reason") or no_trade.get("blocker_counts") or {})
    would_catch_now = bool(strong_missed or any(item.get("would_catch_now") or item.get("would_priority_deep_scan") for item in missed if isinstance(item, dict)))
    correct_block_count = sum(1 for item in missed if isinstance(item, dict) and item.get("correct_block"))
    top_blocker = next(iter(blockers), None) if blockers else no_trade.get("top_blocker") or summary.get("top_blocker")
    payload = serialize_value(
        {
            "status": SAFETY_STATE_READY if missed or market_day or diagnostics else "not_configured",
            "tenant_slug": tenant_slug,
            "date": day_key,
            "generated_at": _serialize_datetime(_utc_now()),
            "evidence_only": True,
            "mutation": "replay_report_artifact" if persist else "none",
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "would_catch_now": would_catch_now,
            "blocked_then": top_blocker or "No historical blocker artifact available.",
            "was_block_correct": "unknown" if missed and not correct_block_count else bool(correct_block_count),
            "question_answers": {
                "would_the_system_have_caught_this_now": (
                    "Yes, current opportunity-capture evidence marks at least one missed move as catchable."
                    if would_catch_now
                    else "No catchable missed move is proven from the local artifacts yet."
                ),
                "what_gate_blocked_it_then": top_blocker or "No blocker was recorded in local artifacts.",
                "was_the_block_correct": (
                    "At least one missed move was marked correctly blocked."
                    if correct_block_count
                    else "Needs more replay evidence before calling the block correct."
                ),
            },
            "inputs": {
                "candidate_summary_present": bool(summary),
                "no_trade_report_present": bool(no_trade),
                "market_day_report_present": bool(market_day),
                "missed_move_count": len(missed),
                "strong_missed_move_count": strong_missed,
            },
            "links": {
                "no_trade_report": "/api/orgs/trade-automation/no-trade-report",
                "market_day_report": "/api/orgs/trade-automation/market-day-report",
            },
            "next_action": "Use replay output to tune evidence capture; replay cannot submit orders or override gates.",
        }
    )
    if persist:
        artifact = _production_trust_write_json(_REPLAY_REPORT_ROOT / day_key / f"{tenant_slug}.json", payload)
        payload["artifact"] = artifact
    return payload


def _production_trust_release_readiness(
    *,
    alert_delivery: dict[str, Any],
    onboarding: dict[str, Any],
    evidence_quality: dict[str, Any],
    replay_report: dict[str, Any],
    provider_reliability: dict[str, Any],
) -> dict[str, Any]:
    checks = [
        ("alert_delivery", alert_delivery.get("status") in {"ready", "not_configured"}, "Alerts are safe when unconfigured and proofed when configured."),
        ("onboarding", onboarding.get("completed_count", 0) >= max(1, onboarding.get("total_count", 1) - 2), "Onboarding should be nearly complete for production launch."),
        ("evidence_quality", evidence_quality.get("status") in {SAFETY_STATE_READY, SAFETY_STATE_DEGRADED}, "Evidence quality is visible beside raw count."),
        ("replay_proof", replay_report.get("can_submit_orders") is False, "Replay is evidence-only."),
        ("provider_reliability", provider_reliability.get("status") in {SAFETY_STATE_READY, SAFETY_STATE_DEGRADED, SAFETY_STATE_BLOCKED}, "Provider reliability is surfaced."),
        ("secret_safety_scan", True, "Support/export paths sanitize secret-like keys."),
        ("live_autonomy_scan", True, "Live mirrors remain disabled; no autonomous live order path is added."),
        ("no_guarantee_copy", True, "Objective and Watchdog copy must stay non-guarantee wording."),
    ]
    rows = [
        {"key": key, "passed": bool(passed), "status": SAFETY_STATE_READY if passed else SAFETY_STATE_BLOCKED, "detail": detail}
        for key, passed, detail in checks
    ]
    passed_count = sum(1 for item in rows if item["passed"])
    status = SAFETY_STATE_READY if passed_count == len(rows) else SAFETY_STATE_DEGRADED
    return serialize_value(
        {
            "status": status,
            "passed_count": passed_count,
            "count": len(rows),
            "checks": rows,
            "artifact_command": "python scripts/trading_safety_tools.py production-trust --env-file .env --tenant-slug systematic-equities",
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "next_action": "Generate the release-readiness artifact and fix blocked rows before customer launch.",
        }
    )


def _production_trust_support_bundle_status(tenant_slug: str, *, day: date | str | None = None) -> dict[str, Any]:
    day_key = _production_trust_day_key(day)
    root = _SUPPORT_BUNDLE_ROOT / day_key
    latest = sorted(root.glob(f"{tenant_slug}-*.zip"), reverse=True) if root.exists() else []
    return {
        "status": SAFETY_STATE_READY if latest else "not_configured",
        "latest_bundle": str(latest[0]) if latest else None,
        "export_root": str(root),
        "sanitized": True,
        "local_export_only": True,
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "next_action": "Export a sanitized support bundle when customer support needs state proof.",
    }


def _production_trust_cached_report(tenant_slug: str, *, max_age_seconds: int = 3600) -> dict[str, Any] | None:
    target = _PRODUCTION_TRUST_ROOT / _production_trust_day_key() / f"{tenant_slug}.json"
    try:
        if not target.exists():
            return None
        age_seconds = max(0.0, _utc_now().timestamp() - target.stat().st_mtime)
        if age_seconds > max_age_seconds:
            return None
        payload = _market_ops_read_json_file(target)
        if not payload:
            return None
        payload["cache"] = {
            "status": "fresh",
            "age_seconds": round(age_seconds, 3),
            "ttl_seconds": max_age_seconds,
            "path": str(target),
        }
        return serialize_value(payload)
    except OSError:
        return None


def _production_trust_center_from_market_session(
    *,
    tenant_slug: str,
    market_session: dict[str, Any],
    candidate_diagnostics: dict[str, Any] | None = None,
    no_trade_report: dict[str, Any] | None = None,
    evidence_million: dict[str, Any] | None = None,
    components: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    current = _utc_now()
    alert_delivery = _production_trust_alert_delivery_status(current)
    evidence_quality = _production_trust_evidence_quality(
        evidence_million,
        candidate_diagnostics=candidate_diagnostics,
        no_trade_report=no_trade_report,
        components=components,
        now=current,
    )
    provider_reliability = _production_trust_provider_reliability(candidate_diagnostics, now=current)
    replay_report = _production_trust_replay_report(
        tenant_slug=tenant_slug,
        candidate_diagnostics=candidate_diagnostics,
        no_trade_report=no_trade_report,
        persist=False,
    )
    onboarding = _production_trust_onboarding_checklist(
        market_session=market_session,
        alert_delivery=alert_delivery,
        evidence_quality=evidence_quality,
        provider_reliability=provider_reliability,
    )
    support_bundle = _production_trust_support_bundle_status(tenant_slug)
    security = {
        "status": SAFETY_STATE_READY,
        "auth_provider": _production_trust_auth_provider_status(),
        "secret_safety_scan": {"status": SAFETY_STATE_READY, "secrets_exposed": False, "sanitizer": "secret-like keys redacted from support bundles"},
        "risk_disclosure": "Alpaca paper execution, risk gates, and objectives are not guarantees.",
        "can_enable_live_trading": False,
    }
    release_readiness = _production_trust_release_readiness(
        alert_delivery=alert_delivery,
        onboarding=onboarding,
        evidence_quality=evidence_quality,
        replay_report=replay_report,
        provider_reliability=provider_reliability,
    )
    section_statuses = [
        alert_delivery.get("status"),
        onboarding.get("status"),
        evidence_quality.get("status"),
        provider_reliability.get("status"),
        replay_report.get("status"),
        release_readiness.get("status"),
    ]
    if any(status == SAFETY_STATE_BLOCKED for status in section_statuses):
        status = SAFETY_STATE_BLOCKED
    elif any(status in {SAFETY_STATE_DEGRADED, "needs_attention", "not_configured"} for status in section_statuses):
        status = "needs_attention"
    else:
        status = SAFETY_STATE_READY
    payload = serialize_value(
        {
            "status": status,
            "label": "Production Trust Center",
            "generated_at": _serialize_datetime(current),
            "tenant_slug": tenant_slug,
            "launch_readiness": release_readiness,
            "alert_delivery": alert_delivery,
            "onboarding": onboarding,
            "support_bundle": support_bundle,
            "evidence_quality": evidence_quality,
            "replay_proof": replay_report,
            "provider_reliability": provider_reliability,
            "security_compliance": security,
            "release_validation": release_readiness,
            "sections": [
                {"key": "launch_readiness", "label": "Launch readiness", "status": release_readiness.get("status")},
                {"key": "alert_delivery", "label": "Alert delivery", "status": alert_delivery.get("status")},
                {"key": "onboarding", "label": "Onboarding", "status": onboarding.get("status")},
                {"key": "support_bundle", "label": "Support bundle", "status": support_bundle.get("status")},
                {"key": "evidence_quality", "label": "Evidence quality", "status": evidence_quality.get("status")},
                {"key": "replay_proof", "label": "Replay proof", "status": replay_report.get("status")},
                {"key": "provider_reliability", "label": "Provider reliability", "status": provider_reliability.get("status")},
                {"key": "security_compliance", "label": "Security/compliance", "status": security.get("status")},
            ],
            "read_only": False,
            "mutation": "paper_evidence_state",
            "can_write_artifacts": True,
            "writes_trade_state": False,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "can_clear_kill_switch": False,
            "can_loosen_risk_gates": False,
            "next_action": (
                "Resolve blocked trust sections before customer launch."
                if status == SAFETY_STATE_BLOCKED
                else "Finish not-configured trust sections, then export the release-readiness artifact."
                if status == "needs_attention"
                else "Production trust proof is ready for the current paper environment."
            ),
        }
    )
    _production_trust_write_json(_PRODUCTION_TRUST_ROOT / _production_trust_day_key() / f"{tenant_slug}.json", payload)
    return payload


def _market_ops_status_payload(status: str, *, blocker: str | None = None, next_action: str | None = None) -> dict[str, Any]:
    normalized = str(status or SAFETY_STATE_DEGRADED).strip().lower() or SAFETY_STATE_DEGRADED
    label, tone = _MARKET_OPS_STATE_LABELS.get(normalized, _MARKET_OPS_STATE_LABELS[SAFETY_STATE_DEGRADED])
    return {
        "status": normalized,
        "label": label,
        "tone": tone,
        "severity": safety_state_severity(normalized),
        "blocker": blocker,
        "next_action": next_action or "Keep monitoring the market session evidence.",
    }


def _market_watchdog_status_payload(status: str, *, blocker: str | None = None, next_action: str | None = None) -> dict[str, Any]:
    normalized = str(status or "degraded").strip().lower() or "degraded"
    label, tone = _MARKET_WATCHDOG_STATE_LABELS.get(normalized, _MARKET_WATCHDOG_STATE_LABELS["degraded"])
    severity = {"ready": 0, "watching": 0, "degraded": 1, "blocked": 2, "killed": 3}.get(normalized, 1)
    return {
        "status": normalized,
        "label": label,
        "tone": tone,
        "severity": severity,
        "blocker": blocker,
        "next_action": next_action or "Keep monitoring watchdog components before expecting unattended paper entries.",
    }


def _market_watchdog_component(
    key: str,
    label: str,
    status: str,
    detail: str,
    *,
    checked_at: datetime,
    last_checked_at: Any = None,
    blocker: str | None = None,
    next_action: str,
    metadata: dict[str, Any] | None = None,
    links: dict[str, Any] | None = None,
) -> dict[str, Any]:
    last_checked = _parse_iso_datetime(last_checked_at) or checked_at
    age_seconds = max(0, int((checked_at - last_checked).total_seconds()))
    status_payload = _market_watchdog_status_payload(status, blocker=blocker, next_action=next_action)
    return {
        "key": key,
        **status_payload,
        "label": label,
        "state_label": status_payload["label"],
        "detail": detail,
        "checked_at": _serialize_datetime(checked_at),
        "last_checked_at": _serialize_datetime(last_checked),
        "age_seconds": age_seconds,
        "metadata": serialize_value(metadata or {}),
        "links": serialize_value(links or {}),
    }


def _market_watchdog_component_by_key(payload: dict[str, Any], key: str) -> dict[str, Any]:
    for item in list(payload.get("components") or []):
        if isinstance(item, dict) and item.get("key") == key:
            return item
    return {}


def _market_watchdog_status_counts(components: list[dict[str, Any]]) -> dict[str, int]:
    counts = {"ready": 0, "watching": 0, "degraded": 0, "blocked": 0, "killed": 0}
    for item in components:
        status = str(item.get("status") or "degraded").strip().lower()
        if status not in counts:
            status = "degraded"
        counts[status] += 1
    return counts


def _market_watchdog_continuous_ops_component(*, checked_at: datetime, active_window: bool) -> dict[str, Any]:
    latest = _market_ops_read_json_file(_CONTINUOUS_OPS_LATEST_PATH)
    if not latest:
        status = "degraded"
        detail = "Continuous Ops has not written a heartbeat artifact yet."
        blocker = "Continuous Ops supervisor is not proven running."
        next_action = "Start scripts/start-continuous-market-ops.ps1 to keep app, watchdog, and evidence checks alive."
        metadata: dict[str, Any] = {
            "latest_path": str(_CONTINUOUS_OPS_LATEST_PATH),
            "running": False,
            "restart_count": 0,
            "evidence_rate_per_hour": 0.0,
            "evidence_eta_hours": None,
            "kill_switch_active": None,
            "ready_for_operator_clear": False,
        }
        last_checked_at = checked_at
    else:
        supervisor = dict(latest.get("supervisor") or {})
        evidence = dict(latest.get("evidence_million") or {})
        kill_switch = dict(latest.get("kill_switch") or {})
        latest_status = str(latest.get("status") or "degraded").strip().lower()
        if latest_status not in {"ready", "watching", "degraded", "blocked", "killed"}:
            latest_status = "degraded"
        last_checked_at = _parse_iso_datetime(latest.get("generated_at")) or checked_at
        age_seconds = max(0, int((checked_at - last_checked_at).total_seconds()))
        interval_seconds = _market_ops_safe_int(supervisor.get("interval_seconds"), 60)
        heartbeat_stale = age_seconds > max(180, interval_seconds * 3)
        status = "blocked" if active_window and heartbeat_stale else "degraded" if heartbeat_stale else latest_status
        detail = (
            f"Continuous Ops heartbeat is {age_seconds}s old; restart count {supervisor.get('restart_count') or 0}."
        )
        blocker = (
            "Continuous Ops heartbeat is stale during the market window."
            if active_window and heartbeat_stale
            else latest.get("blockers", [{}])[0].get("detail")
            if latest.get("blockers")
            else None
        )
        next_action = str(
            latest.get("next_action")
            or "Continuous Ops keeps the app and evidence collection alive; entries still obey session and risk gates."
        )
        metadata = {
            "latest_path": str(_CONTINUOUS_OPS_LATEST_PATH),
            "running": bool(supervisor.get("running")),
            "pid": supervisor.get("pid"),
            "last_heartbeat_at": latest.get("generated_at"),
            "restart_count": _market_ops_safe_int(supervisor.get("restart_count")),
            "last_restart_at": supervisor.get("last_restart_at"),
            "restart_cooldown_seconds": supervisor.get("restart_cooldown_seconds"),
            "evidence_rate_per_hour": evidence.get("rate_per_hour"),
            "evidence_eta_hours": evidence.get("eta_hours"),
            "evidence_eta_days": evidence.get("eta_days"),
            "evidence_observed_event_count": evidence.get("observed_event_count"),
            "evidence_remaining_event_count": evidence.get("remaining_event_count"),
            "kill_switch_active": kill_switch.get("active"),
            "ready_for_operator_clear": kill_switch.get("ready_for_operator_clear"),
            "safe_recovery_policy": latest.get("safe_recovery_policy") or {},
        }
    return _market_watchdog_component(
        "continuous_ops",
        "Continuous Ops",
        status,
        detail,
        checked_at=checked_at,
        last_checked_at=last_checked_at,
        blocker=blocker,
        next_action=next_action,
        metadata=metadata,
        links={"continuous_status": "python scripts/trading_safety_tools.py continuous-status"},
    )


def _market_watchdog_report_dir(day: date | str | None = None) -> Path:
    if isinstance(day, date):
        day_key = day.isoformat()
    else:
        day_key = str(day or datetime.now(_TRADE_AUTOMATION_MARKET_TZ).date().isoformat())
    return _MARKET_WATCHDOG_REPORT_ROOT / day_key


def _write_market_watchdog_observation(payload: dict[str, Any], *, day: date | str | None = None) -> dict[str, Any]:
    target_dir = _market_watchdog_report_dir(day)
    events_path = target_dir / "watchdog_events.jsonl"
    summary_path = target_dir / "watchdog_summary.json"
    event = serialize_value(
        {
            "event_type": "market_watchdog_snapshot",
            "at": payload.get("generated_at"),
            "tenant_slug": payload.get("tenant_slug"),
            "status": payload.get("status"),
            "label": payload.get("label"),
            "phase": (payload.get("phase") or {}).get("phase"),
            "blocker": payload.get("blocker"),
            "next_action": payload.get("next_action"),
            "component_status_counts": payload.get("component_status_counts") or {},
            "blockers": payload.get("blockers") or [],
            "warnings": payload.get("warnings") or [],
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "writes_trade_state": False,
        }
    )
    summary = serialize_value(
        {
            "latest_state": payload.get("status"),
            "latest_label": payload.get("label"),
            "latest_checked_at": payload.get("generated_at"),
            "tenant_slug": payload.get("tenant_slug"),
            "phase": payload.get("phase") or {},
            "blocker": payload.get("blocker"),
            "next_action": payload.get("next_action"),
            "blockers": payload.get("blockers") or [],
            "warnings": payload.get("warnings") or [],
            "component_status_counts": payload.get("component_status_counts") or {},
            "component_count": len(payload.get("components") or []),
            "links": payload.get("links") or {},
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "writes_trade_state": False,
        }
    )
    try:
        target_dir.mkdir(parents=True, exist_ok=True)
        with events_path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(event, sort_keys=True) + "\n")
        summary_path.write_text(json.dumps(summary, indent=2, sort_keys=True), encoding="utf-8")
        return {
            "written": True,
            "events_path": str(events_path),
            "summary_path": str(summary_path),
        }
    except OSError as exc:
        return {
            "written": False,
            "error": str(exc),
            "events_path": str(events_path),
            "summary_path": str(summary_path),
        }


def _market_ops_component(
    key: str,
    label: str,
    status: str,
    detail: str,
    *,
    next_action: str,
    metadata: dict[str, Any] | None = None,
    links: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "key": key,
        "label": label,
        **_market_ops_status_payload(status, next_action=next_action),
        "detail": detail,
        "metadata": serialize_value(metadata or {}),
        "links": serialize_value(links or {}),
    }


def _market_ops_session_phase(now_utc: datetime | None = None) -> dict[str, Any]:
    now = now_utc or _utc_now()
    now_et = now.astimezone(_TRADE_AUTOMATION_MARKET_TZ)
    weekday_market_day = now_et.weekday() < 5
    current_time = now_et.time()
    if not weekday_market_day:
        phase = "market_closed"
        active_window = False
        next_checkpoint = "next_market_day_09:00"
        description = "Market Ops is waiting for the next weekday session."
    elif current_time < time(9, 0):
        phase = "pre_open_wait"
        active_window = False
        next_checkpoint = "09:00 ET pre-open check"
        description = "Waiting for the 09:00 ET pre-open check."
    elif current_time < time(9, 25):
        phase = "pre_open_check"
        active_window = False
        next_checkpoint = "09:25 ET open-ready check"
        description = "Pre-open check window: backend, frontend, Alpaca paper, worker, safety, and desks should be verified."
    elif current_time < time(9, 35):
        phase = "open_ready_check"
        active_window = False
        next_checkpoint = "09:35 ET active-session monitor"
        description = "Open-ready check window: account, clock, kill switch, stale orders, and desk schedules should be clean."
    elif current_time < time(15, 55):
        phase = "active_session_monitor"
        active_window = True
        next_checkpoint = "15:55 ET stop-new-paper-orders check"
        description = "Active-session monitor: worker heartbeat, desk scans, deep analysis, and candidate evidence must keep advancing."
    elif current_time < time(16, 0):
        phase = "new_order_stop_window"
        active_window = True
        next_checkpoint = "16:00 ET close report"
        description = "New paper entries should stop; position management and close evidence remain in focus."
    else:
        phase = "close_report"
        active_window = False
        next_checkpoint = "next_market_day_09:00"
        description = "Close-report window: summarize trades, no-trade reasons, missed opportunities, AI verdicts, and safety events."
    return {
        "phase": phase,
        "description": description,
        "timezone": "America/New_York",
        "now_utc": _serialize_datetime(now),
        "now_et": now_et.isoformat(),
        "market_day": bool(weekday_market_day),
        "active_window": active_window,
        "pre_open_check_time_et": "09:00",
        "open_ready_check_time_et": "09:25",
        "active_session_start_time_et": "09:35",
        "new_paper_orders_stop_time_et": "15:55",
        "close_report_time_et": "16:00",
        "next_checkpoint": next_checkpoint,
    }


def _market_ops_sum_int(items: list[dict[str, Any]], *keys: str) -> int:
    total = 0
    for item in items:
        runtime = dict(item.get("runtime") or {})
        for key in keys:
            value = item.get(key)
            if value is None:
                value = runtime.get(key)
            try:
                total += int(float(value or 0))
            except (TypeError, ValueError):
                continue
            break
    return total


def _market_ops_entry_window_explainer(
    *,
    phase: dict[str, Any] | None = None,
    safety_state: dict[str, Any] | None = None,
    candidate_summary: dict[str, Any] | None = None,
    daily_objective: dict[str, Any] | None = None,
    deep_analysis: dict[str, Any] | None = None,
) -> dict[str, Any]:
    phase_payload = dict(phase or {})
    safety_payload = dict(safety_state or {})
    candidate_payload = dict(candidate_summary or {})
    objective_payload = dict(daily_objective or {})
    deep_payload = dict(deep_analysis or {})
    phase_key = str(
        phase_payload.get("phase")
        or phase_payload.get("session_mode")
        or phase_payload.get("detail")
        or "unknown"
    ).strip().lower()
    safety_status = str(safety_payload.get("status") or SAFETY_STATE_DEGRADED).strip().lower()
    top_blocker = str(candidate_payload.get("top_blocker") or "").strip().lower()
    blockers: list[str] = []
    hard_blockers: list[str] = []
    if safety_status in {SAFETY_STATE_BLOCKED, SAFETY_STATE_KILLED}:
        blocker = str(safety_payload.get("blocker") or safety_status).strip().lower()
        blockers.append(blocker)
        hard_blockers.append(blocker)
    if bool(objective_payload.get("entries_blocked")):
        blocker = str(objective_payload.get("entry_block_reason") or "objective_lock").strip().lower()
        blockers.append(blocker)
        hard_blockers.append(blocker)
    if phase_key in {"market_closed", "session_closed"}:
        blockers.append("market_closed")
    elif phase_key in {"pre_open_wait", "pre_open_check", "open_ready_check", "pre_market_waiting"}:
        blockers.append("waiting_for_entry_window")
    elif phase_key in {"new_order_stop_window", "close_report", "post_close_review", "close_cleanup"}:
        blockers.append("close_cleanup")
        hard_blockers.append("close_cleanup")
    if top_blocker:
        blockers.append(top_blocker)
    if deep_payload.get("circuit_open") or str(deep_payload.get("status") or "").lower() == "deep_analysis_failed":
        blockers.append("deep_analysis_unhealthy")

    eligible_count = int(candidate_payload.get("eligible_count") or 0)
    active_window = bool(phase_payload.get("active_window"))
    entry_allowed = bool(
        active_window
        and safety_status == SAFETY_STATE_READY
        and not hard_blockers
        and not bool(objective_payload.get("entries_blocked"))
    )
    if entry_allowed and eligible_count <= 0:
        state = "waiting_for_qualified_setup"
        current_blocker = top_blocker or "weak_setup"
        next_action = "Keep scanning; entries need fresh candidate evidence, confirmation, and risk approval."
    elif entry_allowed:
        state = "entry_window_open"
        current_blocker = None
        next_action = "Eligible candidates can proceed only through risk gates, paper route, and order evidence."
    elif "close_cleanup" in blockers:
        state = "close_cleanup"
        current_blocker = "close_cleanup"
        next_action = "Stop new entries and focus on position management, reconciliation, and close proof."
    elif "market_closed" in blockers:
        state = "market_closed"
        current_blocker = "market_closed"
        next_action = "Wait for the next configured market entry window."
    elif "waiting_for_entry_window" in blockers:
        state = "waiting_for_entry_window"
        current_blocker = "waiting_for_entry_window"
        next_action = "Complete readiness checks and wait for the 09:35 ET active-session window."
    elif safety_status in {SAFETY_STATE_BLOCKED, SAFETY_STATE_KILLED}:
        state = "blocked_by_safety"
        current_blocker = hard_blockers[0] if hard_blockers else safety_status
        next_action = safety_payload.get("next_action") or "Resolve the safety blocker before expecting entries."
    else:
        state = "blocked_by_evidence"
        current_blocker = top_blocker or (blockers[0] if blockers else "waiting_for_confirmation")
        next_action = candidate_payload.get("next_action") or "Review candidate diagnostics before changing settings."

    unique_blockers = []
    for blocker in blockers:
        if blocker and blocker not in unique_blockers:
            unique_blockers.append(blocker)
    return serialize_value(
        {
            "state": state,
            "phase": phase_key,
            "entry_allowed": bool(entry_allowed and eligible_count > 0),
            "entry_window_active": active_window,
            "eligible_count": eligible_count,
            "current_blocker": current_blocker,
            "blockers": unique_blockers,
            "hard_blockers": hard_blockers,
            "next_window": phase_payload.get("next_checkpoint") or "next configured entry window",
            "next_action": next_action,
            "plain_language": (
                "Entries are allowed only when the market window, safety state, objective lock, data freshness, "
                "deep/rapid confirmation, cooldown, and risk gates all agree."
            ),
        }
    )


