        _item("Risk Allocator", "remaining_entry_budget", "Remaining entry budget widget", status=_status(True), evidence={"source": "weekly objective plus max entries", "entries_blocked": (diagnostics.get("daily_objective") or {}).get("entries_blocked")}),
