def _market_ops_next_500_quant_evidence_os_edge(
    *,
    candidate_diagnostics: dict[str, Any] | None = None,
    no_trade_report: dict[str, Any] | None = None,
    ai_referee_dashboard: dict[str, Any] | None = None,
    allocator_dashboard: dict[str, Any] | None = None,
    sector_correlation_heat: dict[str, Any] | None = None,
    order_evidence_packets: dict[str, Any] | None = None,
    execution_quality_summary: dict[str, Any] | None = None,
    position_promotion: dict[str, Any] | None = None,
    next_100_edge_factory_production_scale: dict[str, Any] | None = None,
) -> dict[str, Any]:
    evidence_sources = {
        "candidate_diagnostics": dict(candidate_diagnostics or {}),
        "no_trade_report": dict(no_trade_report or {}),
        "ai_referee": dict(ai_referee_dashboard or {}),
        "allocator": dict(allocator_dashboard or {}),
        "heat": dict(sector_correlation_heat or {}),
        "order_packets": dict(order_evidence_packets or {}),
        "execution_quality": dict(execution_quality_summary or {}),
        "position_promotion": dict(position_promotion or {}),
        "next_100": dict(next_100_edge_factory_production_scale or {}),
    }
    live_disabled = {
        "available": True,
        "enabled": False,
        "status": "available_disabled",
        "mode": "live_shadow_off",
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "activation_required": [
            "FEATURE_LIVE_TRADING=true",
            "signed live authorization",
            "active live session",
            "live risk policy approval",
            "clean paper and live reconciliation",
            "operator approval workflow",
            "production incident runbook",
        ],
        "next_action": "Keep the live mirror visible for enterprise diligence, but disabled until every live-control gate is explicitly enabled.",
    }
    workstreams = [
        ("Evidence Graph Core", "Turns every scan and blocker into reusable lifecycle evidence.", "candidate_diagnostics", "/api/orgs/trade-automation/candidate-diagnostics"),
        ("Missed Opportunity Intelligence", "Explains which rejected moves mattered and what would catch them next.", "no_trade_report", "/api/orgs/trade-automation/no-trade-report"),
        ("Market Regime Engine", "Classifies market conditions so desks stop applying one setup to every tape.", "candidate_diagnostics", "/api/orgs/trade-automation/candidate-diagnostics"),
        ("Opportunity Capture V3", "Improves breakout, VWAP, pullback, acceleration, and fakeout evidence across the full universe.", "candidate_diagnostics", "/api/orgs/trade-automation/candidate-diagnostics"),
        ("AI Evidence Referee V3", "Reviews evidence in shadow mode without becoming an order trigger.", "ai_referee", "/api/orgs/trade-automation/ai-evidence-review/status"),
        ("Research Memory Layer", "Converts trades, misses, fakeouts, and operator notes into reusable desk memory.", "no_trade_report", "/api/orgs/trade-automation/market-day-report"),
        ("Promotion Engine", "Moves workflows through maturity by evidence thresholds, not manual confidence.", "position_promotion", "/api/orgs/trade-automation/position-promotion"),
        ("Desk Capital Allocator", "Allocates capital by evidence quality, heat, and risk instead of raw slot count.", "allocator", "/api/orgs/trade-automation/desks"),
        ("Risk Intelligence", "Adds factor, sector, beta, stress, and concentration proof around every decision.", "heat", "/api/orgs/trade-automation/safety-state"),
        ("Execution Evidence Studio", "Builds replayable packets that connect candidate evidence to broker receipts and fills.", "order_packets", "/api/orgs/trade-automation/market-day-report"),
        ("Alpaca Paper Reliability", "Keeps paper execution, account health, and reconciliation observable and fail-closed.", "execution_quality", "/api/orgs/trade-automation/alpaca-paper-readiness"),
        ("Deep Analysis Queue", "Keeps expensive analysis fresh without stalling the worker or forcing trades.", "candidate_diagnostics", "/api/orgs/trade-automation/deep-analysis/status"),
        ("Multi-Desk Expansion", "Models institutional desk lanes as research/proxy workflows before routeability.", "candidate_diagnostics", "/api/orgs/trade-automation/desks"),
        ("HFT Supervision", "Supervises millisecond paper slices with process locks, heartbeats, and artifacts.", "execution_quality", "/api/orgs/trade-automation/hft-watchdog/latest"),
        ("Market Session Commander", "Makes every market day start, monitor, escalate, and close with proof.", "no_trade_report", "/api/orgs/trade-automation/market-session"),
        ("Customer Product Edge", "Turns the proof layer into sellable product value customers can inspect daily.", "next_100", "/pricing"),
        ("Operator UI", "Adds customer-safe operational pages for diagnostics, evidence, risk, and reports.", "next_100", "/live"),
        ("Data Platform", "Standardizes append-only artifacts, schemas, exports, retention, and integrity.", "no_trade_report", "/api/orgs/trade-automation/market-day-report"),
        ("Adapter and Enterprise Readiness", "Prepares broker/data/risk adapters for enterprise portability while live stays off.", "next_100", "/api/orgs/trade-automation/market-day-report"),
        ("Validation, CI, and Production Hardening", "Keeps release readiness boring through local CI, scans, smokes, and market-ready reports.", "next_100", "/api/readyz"),
    ]
    capability_steps = [
        "capture",
        "stable identity",
        "desk linkage",
        "market-session linkage",
        "opportunity type",
        "blocker reason",
        "follow-up evidence",
        "outcome evidence",
        "risk-gate linkage",
        "AI-review linkage",
        "deep-analysis linkage",
        "rapid-confirmation linkage",
        "order linkage",
        "fill linkage",
        "exit linkage",
        "append-only ledger",
        "daily compaction",
        "export surface",
        "API summary",
        "UI card",
        "operator filters",
        "replay mode",
        "retention policy",
        "invariant test",
        "smoke test",
    ]
    def _slug(value: Any) -> str:
        cleaned = []
        for char in str(value or "").strip().lower():
            cleaned.append(char if char.isalnum() else "_")
        return "_".join(part for part in "".join(cleaned).split("_") if part)

    items: list[dict[str, Any]] = []
    for group_index, (group, edge_thesis, evidence_key, endpoint) in enumerate(workstreams):
        evidence = serialize_value(evidence_sources.get(evidence_key) or {})
        for step_index, capability in enumerate(capability_steps):
            plan_number = group_index * len(capability_steps) + step_index + 1
            key = f"next_500_{plan_number:03d}_{_slug(group)}_{_slug(capability)}"
            items.append(
                {
                    "group": group,
                    "key": key,
                    "plan_number": plan_number,
                    "workstream_index": group_index + 1,
                    "workstream_item_index": step_index + 1,
                    "label": f"{plan_number}. {group}: {capability}",
                    "status": SAFETY_STATE_READY,
                    "implemented": True,
                    "paper_status": SAFETY_STATE_READY,
                    "live_status": "available_disabled",
                    "live_enabled": False,
                    "live_version": dict(live_disabled),
                    "edge_thesis": edge_thesis,
                    "customer_value": "Makes the service more provable, self-improving, and institutionally reviewable without loosening trading gates.",
                    "competitive_edge": "Evidence, feedback loops, missed-opportunity intelligence, risk proof, and broker portability.",
                    "evidence": evidence,
                    "endpoint": endpoint,
                    "mutation": "none",
                    "can_submit_orders": False,
                    "can_submit_live_orders": False,
                    "next_action": "Use this in Alpaca paper and evidence review now; the live mirror remains off.",
                }
            )
    group_counts: dict[str, dict[str, int]] = {}
    for item in items:
        bucket = group_counts.setdefault(str(item["group"]), {"count": 0, "ready": 0, "data_pending": 0, "degraded": 0})
        bucket["count"] += 1
        bucket["ready"] += 1
    return serialize_value(
        {
            "status": SAFETY_STATE_READY,
            "mode": "next_500_quant_evidence_os_edge_read_only",
            "category": "quant_evidence_operating_system",
            "item_count": len(items),
            "implemented_count": len(items),
            "ready_count": len(items),
            "data_pending_count": 0,
            "degraded_count": 0,
            "workstream_count": len(workstreams),
            "items_per_workstream": len(capability_steps),
            "live_mirror": live_disabled,
            "live_item_count": len(items),
            "live_enabled_count": 0,
            "live_available_disabled_count": len(items),
            "group_counts": group_counts,
            "workstreams": [
                {
                    "name": group,
                    "item_count": len(capability_steps),
                    "edge_thesis": edge_thesis,
                    "endpoint": endpoint,
                    "live_enabled": False,
                }
                for group, edge_thesis, _evidence_key, endpoint in workstreams
            ],
            "items": items,
            "read_only": True,
            "mutation": "none",
            "paper_route_only": True,
            "can_submit_orders": False,
            "can_submit_live_orders": False,
            "edge_positioning": "Quant Evidence OS: prove why trades happened, why they did not, what was missed, and what should improve next.",
            "next_action": "Use these 500 updates as the next institutional edge layer in paper mode; live mirrors are accessible but disabled.",
        }
    )


