        ("Missed Edge Learning", "no_trade_report", "/api/orgs/trade-automation/no-trade-report", "Learns from rejected setups, follow-up moves, correct blocks, and bad misses without forcing trades."),
        ("Regime And Breadth Intelligence", "candidate_diagnostics", "/api/orgs/trade-automation/candidate-diagnostics", "Uses market regime, breadth, sector leadership, and ETF confirmation to improve paper priority."),
        ("AI Referee Calibration", "ai_referee", "/api/orgs/trade-automation/ai-evidence-review/status", "Calibrates AI evidence verdicts against outcomes while blocking AI from order authority."),
        ("Allocator Governance", "allocator", "/api/orgs/trade-automation/desks", "Ranks desk capital requests by evidence quality, heat, risk cleanliness, and missed edge."),
        ("Sector Correlation Heat", "heat", "/api/orgs/trade-automation/desks", "Penalizes crowded symbols, sectors, and correlation buckets before capital assignment."),
        ("Execution Quality Memory", "execution_quality", "/api/orgs/trade-automation/market-day-report", "Feeds slippage, fill, timing, and reconciliation evidence into ranking and reports."),
        ("Portfolio Outcome Learning", "portfolio_outcome_intelligence", "/api/orgs/trade-automation/market-session", "Uses portfolio risk fit, drawdown resilience, capital efficiency, and outcome memory."),
        ("Deep Confirmation Governance", "candidate_diagnostics", "/api/orgs/trade-automation/deep-analysis/status", "Monitors deep and rapid confirmation freshness, failures, priority, and blockers."),
        ("Market Session Command", "no_trade_report", "/api/orgs/trade-automation/market-session", "Connects pre-open, active session, no-trade escalation, close proof, and incident timelines."),
        ("Risk Objective Guardrails", "heat", "/api/orgs/trade-automation/safety-state", "Keeps target lock, loss lock, open heat, cooldown, reconciliation, and route gates authoritative."),
        ("Order Evidence Studio", "execution_quality", "/api/orgs/trade-automation/market-day-report", "Packages candidate evidence, risk gates, AI review, broker receipt, and reconciliation proof."),
