def _production_trust_recent_logs(max_files: int = 8, max_bytes: int = 4096) -> list[dict[str, Any]]:
    roots = [Path("runtime"), Path("runtime-logs"), Path("logs")]
    files: list[Path] = []
    for root in roots:
        if not root.exists():
            continue
        try:
            files.extend(path for path in root.rglob("*") if path.is_file() and path.suffix.lower() in {".log", ".txt", ".json"})
        except OSError:
            continue
    latest = sorted(files, key=lambda item: item.stat().st_mtime if item.exists() else 0, reverse=True)[:max_files]
    rows: list[dict[str, Any]] = []
    for path in latest:
        try:
            raw = path.read_text(encoding="utf-8", errors="ignore")[-max_bytes:]
        except OSError:
            continue
        redacted_tail = "\n".join(
            "[redacted secret-like log line]"
            if any(marker in line.lower() for marker in _PRODUCTION_TRUST_SECRET_MARKERS)
            else line
            for line in raw.splitlines()
        )
        rows.append(
            {
                "path": str(path),
                "tail": redacted_tail,
                "bytes_included": len(redacted_tail.encode("utf-8", errors="ignore")),
            }
        )
    return rows


def export_tenant_trade_automation_support_bundle(
    db: Session,
    *,
    current_user: Any,
) -> dict[str, Any]:
    _assert_trade_automation_operator(current_user)
    tenant = _resolve_tenant_for_current_user(db, current_user)
    now = _utc_now()
    day = now.astimezone(_TRADE_AUTOMATION_MARKET_TZ).date()
    timestamp = now.strftime("%H%M%S")
    target_dir = _SUPPORT_BUNDLE_ROOT / day.isoformat() / f"{tenant.slug}-{timestamp}"
    market_session = get_tenant_trade_automation_market_session(db, current_user=current_user)
    watchdog = get_tenant_trade_automation_watchdog(db, current_user=current_user)
    no_trade_report = get_tenant_trade_automation_no_trade_report(db, current_user=current_user)
    candidate_diagnostics = get_tenant_trade_automation_candidate_diagnostics(db, current_user=current_user)
    production_trust = market_session.get("production_trust") or {}
    bundle_parts = {
        "manifest": {
            "tenant_slug": tenant.slug,
            "generated_at": _serialize_datetime(now),
            "sanitized": True,
            "local_export_only": True,
            "excluded": [".env values", "broker credentials", "raw API keys", "tokens", "authorization headers"],
            "can_submit_orders": False,
            "can_submit_live_orders": False,
        },
        "watchdog": watchdog,
        "market_session": market_session,
        "safety_state": market_session.get("safety_state") or {},
        "daily_ledger_summary": build_trading_safety_daily_summary(day=day, tenant_slug=tenant.slug),
        "no_trade_report": no_trade_report,
        "candidate_diagnostics_summary": {
            "source": candidate_diagnostics.get("source"),
            "evaluated_at": candidate_diagnostics.get("evaluated_at"),
            "summary": candidate_diagnostics.get("summary") or {},
            "universe": candidate_diagnostics.get("universe") or {},
        },
        "alpaca_paper_readiness": build_alpaca_paper_readiness_snapshot(),
        "evidence_million": market_session.get("evidence_million_target") or {},
        "evidence_quality": production_trust.get("evidence_quality") or {},
        "production_trust": production_trust,
        "backend_readyz": {
            "status": "ready",
            "source": "support_bundle_export",
            "readiness_cache": market_session.get("readiness_cache") or {},
        },
        "env_key_presence": {
            "alpaca_key_present": bool(_production_trust_env_value("APCA_API_KEY_ID", "ALPACA_API_KEY_ID", "ALPACA_API_KEY")),
            "alpaca_secret_present": bool(_production_trust_env_value("APCA_API_SECRET_KEY", "ALPACA_API_SECRET_KEY", "ALPACA_SECRET_KEY")),
            "smtp_or_webhook_configured": bool((production_trust.get("alert_delivery") or {}).get("enabled")),
            "secrets_exposed": False,
        },
        "recent_logs": {"items": _production_trust_recent_logs()},
    }
    sanitized_parts = {name: _production_trust_sanitize(payload, key_hint=name) for name, payload in bundle_parts.items()}
    target_dir.mkdir(parents=True, exist_ok=True)
    written: list[dict[str, Any]] = []
    for name, payload in sanitized_parts.items():
        target = target_dir / f"{name}.json"
        result = _production_trust_write_json(target, payload if isinstance(payload, dict) else {"value": payload})
        written.append({"key": name, **result})
    zip_path = target_dir.with_suffix(".zip")
    try:
        with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as archive:
            for file in target_dir.glob("*.json"):
                archive.write(file, arcname=file.name)
        zip_result = {"written": True, "path": str(zip_path)}
    except OSError as exc:
        zip_result = {"written": False, "path": str(zip_path), "error": str(exc)}
    payload = {
        "ok": bool(zip_result.get("written")),
        "status": SAFETY_STATE_READY if zip_result.get("written") else SAFETY_STATE_DEGRADED,
        "tenant_slug": tenant.slug,
        "generated_at": _serialize_datetime(now),
        "directory": str(target_dir),
        "zip": zip_result,
        "files": written,
        "sanitized": True,
        "local_export_only": True,
        "secret_safety_scan": {"status": SAFETY_STATE_READY, "secrets_exposed": False},
        "can_submit_orders": False,
        "can_submit_live_orders": False,
        "next_action": "Attach the sanitized ZIP to support; it excludes .env values and broker credentials.",
    }
    _production_trust_write_json(target_dir / "support_bundle_export.json", payload)
    return serialize_value(payload)


