def update_tenant_trade_automation_desk(
    db: Session,
    *,
    current_user: Any,
    desk_key: str,
    updates: Any,
) -> dict[str, Any]:
    _assert_trade_automation_operator(current_user)
    tenant = _resolve_tenant_for_current_user(db, current_user)
    actor = _resolve_user_for_current_user(db, current_user)
    normalized_key = _normalize_trade_automation_desk_key(desk_key)
    payload = updates.model_dump(exclude_unset=True) if hasattr(updates, "model_dump") else dict(updates or {})
    desks = _read_trade_automation_desks_store(tenant)
    current = dict(desks[normalized_key].get("settings") or {})
    for key in (
        "enabled",
        "armed",
        "interval",
        "cycle_interval_seconds",
        "market_aware_schedule",
        "macro_signal_refresh_time_et",
        "macro_entry_scan_time_et",
        "macro_preclose_review_time_et",
        "macro_new_entries_after_time_et",
        "macro_new_entries_before_time_et",
        "deep_scan_limit",
        "max_hold_minutes",
        "cooldown_minutes",
        "risk_budget_pct",
        "max_open_notional_pct",
        "max_positions",
        "allowed_tickers",
        "strategy_family",
        "objective_role",
    ):
        if key in payload:
            current[key] = payload.get(key)
    desks[normalized_key]["settings"] = _normalize_trade_automation_desk_settings(normalized_key, current)
    _write_trade_automation_desks_store(tenant, desks)
    record_audit_event(
        db,
        event_type="trade_automation.desk_updated",
        tenant=tenant,
        user=actor,
        payload={
            "desk_key": normalized_key,
            "updated_fields": sorted(payload.keys()),
            "settings": serialize_value(desks[normalized_key]["settings"]),
        },
    )
    db.commit()
    db.refresh(tenant)
    return _build_trade_automation_desk_summary(
        normalized_key,
        _read_trade_automation_desks_store(tenant)[normalized_key],
        now=_utc_now(),
    )


